                    <div className="flex items-center gap-3">
                      <div className="w-9 h-9 shimmer rounded-lg shrink-0" />
                      <div className="flex-1 space-y-2">
                        <div className="h-4 shimmer rounded w-1/3" />
                        <div className="h-3 shimmer rounded w-1/4" />
                      </div>
