          </motion.div>

          <BlockchainStatusSection />

          <div className="pt-4 border-t border-border/50 text-center">
            <p className="text-[11px] text-muted-foreground/50">
              DW Media Studio Developer Portal
            </p>
          </div>
        </main>
      </div>
    </>
  );
}

