import { z } from 'zod';
import { insertMediaSchema, insertCollectionSchema, mediaItems, collections } from './schema';

export const errorSchemas = {
  validation: z.object({
    message: z.string(),
    field: z.string().optional(),
  }),
  notFound: z.object({
    message: z.string(),
  }),
  internal: z.object({
    message: z.string(),
  }),
  unauthorized: z.object({
    message: z.string(),
  }),
};

export const api = {
  media: {
    list: {
      method: 'GET' as const,
      path: '/api/media' as const,
      responses: {
        200: z.array(z.custom<typeof mediaItems.$inferSelect>()),
        401: errorSchemas.unauthorized,
      },
    },
    get: {
      method: 'GET' as const,
      path: '/api/media/:id' as const,
      responses: {
        200: z.custom<typeof mediaItems.$inferSelect>(),
        404: errorSchemas.notFound,
        401: errorSchemas.unauthorized,
      },
    },
    create: {
      method: 'POST' as const,
      path: '/api/media' as const,
      input: insertMediaSchema,
      responses: {
        201: z.custom<typeof mediaItems.$inferSelect>(),
        400: errorSchemas.validation,
        401: errorSchemas.unauthorized,
      },
    },
    update: {
      method: 'PATCH' as const,
      path: '/api/media/:id' as const,
      input: z.object({
        title: z.string().optional(),
        description: z.string().optional(),
        label: z.string().optional(),
        tags: z.array(z.string()).optional(),
        artist: z.string().optional(),
        venue: z.string().optional(),
        tour: z.string().optional(),
        eventDate: z.string().optional(),
        thumbnailUrl: z.string().optional(),
        durationSeconds: z.number().optional(),
      }),
      responses: {
        200: z.custom<typeof mediaItems.$inferSelect>(),
        404: errorSchemas.notFound,
        401: errorSchemas.unauthorized,
      },
    },
    delete: {
      method: 'DELETE' as const,
      path: '/api/media/:id' as const,
      responses: {
        204: z.void(),
        404: errorSchemas.notFound,
        401: errorSchemas.unauthorized,
      },
    },
    toggleFavorite: {
      method: 'PATCH' as const,
      path: '/api/media/:id/favorite' as const,
      input: z.object({ isFavorite: z.boolean() }),
      responses: {
        200: z.custom<typeof mediaItems.$inferSelect>(),
        404: errorSchemas.notFound,
        401: errorSchemas.unauthorized,
      },
    },
    batchUpdate: {
      method: 'PATCH' as const,
      path: '/api/media/batch' as const,
      input: z.object({
        ids: z.array(z.number()),
        updates: z.object({
          isFavorite: z.boolean().optional(),
          label: z.string().optional(),
          tags: z.array(z.string()).optional(),
        }),
      }),
      responses: {
        200: z.array(z.custom<typeof mediaItems.$inferSelect>()),
        401: errorSchemas.unauthorized,
      },
    },
    batchDelete: {
      method: 'DELETE' as const,
      path: '/api/media/batch' as const,
      input: z.object({ ids: z.array(z.number()) }),
      responses: {
        204: z.void(),
        401: errorSchemas.unauthorized,
      },
    },
  },
  collections: {
    list: {
      method: 'GET' as const,
      path: '/api/collections' as const,
      responses: {
        200: z.array(z.custom<typeof collections.$inferSelect>()),
        401: errorSchemas.unauthorized,
      },
    },
    get: {
      method: 'GET' as const,
      path: '/api/collections/:id' as const,
      responses: {
        200: z.custom<typeof collections.$inferSelect>(),
        404: errorSchemas.notFound,
        401: errorSchemas.unauthorized,
      },
    },
    create: {
      method: 'POST' as const,
      path: '/api/collections' as const,
      input: insertCollectionSchema,
      responses: {
        201: z.custom<typeof collections.$inferSelect>(),
        401: errorSchemas.unauthorized,
      },
    },
    update: {
      method: 'PATCH' as const,
      path: '/api/collections/:id' as const,
      input: z.object({
        name: z.string().optional(),
        description: z.string().optional(),
        coverMediaId: z.number().optional(),
      }),
      responses: {
        200: z.custom<typeof collections.$inferSelect>(),
        404: errorSchemas.notFound,
        401: errorSchemas.unauthorized,
      },
    },
    delete: {
      method: 'DELETE' as const,
      path: '/api/collections/:id' as const,
      responses: {
        204: z.void(),
        404: errorSchemas.notFound,
        401: errorSchemas.unauthorized,
      },
    },
    items: {
      method: 'GET' as const,
      path: '/api/collections/:id/items' as const,
      responses: {
        200: z.array(z.custom<typeof mediaItems.$inferSelect>()),
        401: errorSchemas.unauthorized,
      },
    },
    addItems: {
      method: 'POST' as const,
      path: '/api/collections/:id/items' as const,
      input: z.object({ mediaItemIds: z.array(z.number()) }),
      responses: {
        200: z.object({ added: z.number() }),
        401: errorSchemas.unauthorized,
      },
    },
    removeItems: {
      method: 'DELETE' as const,
      path: '/api/collections/:id/items' as const,
      input: z.object({ mediaItemIds: z.array(z.number()) }),
      responses: {
        204: z.void(),
        401: errorSchemas.unauthorized,
      },
    },
  },
};

export function buildUrl(path: string, params?: Record<string, string | number>): string {
  let url = path;
  if (params) {
    Object.entries(params).forEach(([key, value]) => {
      if (url.includes(`:${key}`)) {
        url = url.replace(`:${key}`, String(value));
      }
    });
  }
  return url;
}

export type MediaInput = z.infer<typeof api.media.create.input>;
export type MediaResponse = z.infer<typeof api.media.create.responses[201]>;

server/services/orbitClient.ts.content:
interface WorkerData {
  id: string;
  firstName: string;
  lastName: string;
  email?: string;
  phone?: string;
  status: string;
  payRate?: number;
  workState?: string;
  certifications?: string[];
}

interface TimesheetData {
  id: string;
  workerId: string;
  date: string;
  hoursWorked: number;
  overtimeHours?: number;
  jobId?: string;
  status: string;
}

interface ContractorData {
  id: string;
  firstName: string;
  lastName: string;
  email: string;
  phone?: string;
  ein?: string;
  businessName?: string;
  payRate: number;
  workState: string;
}

interface FinancialTransaction {
  transactionId: string;
  amount: number;
  currency: string;
  description: string;
  category: string;
  timestamp: string;
}

export class OrbitEcosystemClient {
  private hubUrl: string;
  private apiKey: string;
  private apiSecret: string;
  private appName: string;

  constructor(appName: string) {
    this.hubUrl = process.env.ORBIT_HUB_URL || "https://orbitstaffing.replit.app";
    this.apiKey = process.env.ORBIT_ECOSYSTEM_API_KEY || "";
    this.apiSecret = process.env.ORBIT_ECOSYSTEM_API_SECRET || "";
    this.appName = appName;
  }

  get isConfigured(): boolean {
    return !!(this.apiKey && this.apiSecret);
  }

  private get headers(): Record<string, string> {
    return {
      "Content-Type": "application/json",
      "X-API-Key": this.apiKey,
      "X-API-Secret": this.apiSecret,
      "X-App-Name": this.appName,
    };
  }

  private async request(method: string, path: string, body?: any) {
    const url = `${this.hubUrl}${path}`;
    const res = await fetch(url, {
      method,
      headers: this.headers,
      body: body ? JSON.stringify(body) : undefined,
    });
    if (!res.ok) {
      const err = await res.json().catch(() => ({ error: res.statusText }));
      throw new Error(`ORBIT API ${method} ${path} failed: ${JSON.stringify(err)}`);
    }
    return res.json();
  }

  async checkConnection() {
    return this.request("GET", "/api/ecosystem/status");
  }

  async syncWorkers(workers: WorkerData[]) {
    return this.request("POST", "/api/ecosystem/sync/workers", { workers });
  }

  async syncContractors(contractors: ContractorData[]) {
    return this.request("POST", "/api/ecosystem/sync/contractors", { contractors });
  }

  async syncTimesheets(timesheets: TimesheetData[]) {
    return this.request("POST", "/api/ecosystem/sync/timesheets", { timesheets });
  }

  async syncCertifications(certs: { workerId: string; name: string; issuedDate: string; expirationDate?: string }[]) {
    return this.request("POST", "/api/ecosystem/sync/certifications", { certifications: certs });
  }

  async syncW2(w2Data: any[]) {
    return this.request("POST", "/api/ecosystem/sync/w2", { w2Data });
  }

  async sync1099(data1099: any[]) {
    return this.request("POST", "/api/ecosystem/sync/1099", { contractors: data1099 });
  }

  async getShopWorkers(shopId: string) {
    return this.request("GET", `/api/ecosystem/shops/${shopId}/workers`);
  }

  async getShopPayroll(shopId: string) {
    return this.request("GET", `/api/ecosystem/shops/${shopId}/payroll`);
  }

  async reportTransaction(tx: FinancialTransaction) {
    return this.request("POST", "/api/ecosystem/sync/financial-transaction", tx);
  }

  async getFinancialStatement(params?: { period?: string; format?: string }) {
    const query = params ? "?" + new URLSearchParams(params as any).toString() : "";
    return this.request("GET", `/api/ecosystem/financial-statement${query}`);
  }

  async getSnippets() {
    return this.request("GET", "/api/ecosystem/snippets");
  }

  async pushSnippet(snippet: { title: string; language: string; code: string; description?: string }) {
    return this.request("POST", "/api/ecosystem/snippets", snippet);
  }

  async getLogs() {
    return this.request("GET", "/api/ecosystem/logs");
  }

  async pushLog(log: { action: string; details?: any }) {
    return this.request("POST", "/api/ecosystem/logs", log);
  }
}

export const orbitClient = new OrbitEcosystemClient("Trust Vault");

