import { useState, useCallback, useRef } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Badge } from "@/components/ui/badge";
import { useCreateMedia } from "@/hooks/use-media";
import { useUpload } from "@/hooks/use-upload";
import { detectCategory, type MediaCategory } from "@shared/schema";
import {
  Loader2, UploadCloud, CheckCircle, AlertCircle, Film, Music,
  ImageIcon, FileText, File, X, ChevronDown, ChevronUp, Clock,
  MapPin, Mic2, Route, Sparkles
} from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { useSoundFeedback } from "@/hooks/use-sound-feedback";
import { motion, AnimatePresence } from "framer-motion";

const MAX_BATCH_SIZE = 10;

const CATEGORY_CONFIG: Record<MediaCategory, { icon: any; color: string; label: string }> = {
  video: { icon: Film, color: "text-blue-400", label: "Video" },
  audio: { icon: Music, color: "text-green-400", label: "Audio" },
  image: { icon: ImageIcon, color: "text-purple-400", label: "Image" },
  document: { icon: FileText, color: "text-amber-400", label: "Document" },
  other: { icon: File, color: "text-muted-foreground", label: "File" },
};

const ALL_ACCEPT = "video/*,audio/*,image/*,.pdf,.doc,.docx,.txt,.xls,.xlsx,.ppt,.pptx,.csv,.zip,.rar";

type FileStatus = "pending" | "extracting" | "uploading" | "complete" | "error";

interface QueuedFile {
  id: string;
  file: File;
  category: MediaCategory;
  status: FileStatus;
  progress: number;
  error?: string;
  thumbnailBlob?: Blob | null;
  durationSeconds?: number;
  title: string;
}

function formatFileSize(bytes: number): string {
  if (bytes < 1024) return `${bytes} B`;
  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
}

function extractVideoMetadata(file: File): Promise<{ thumbnail: Blob | null; duration: number }> {
  return new Promise((resolve) => {
    const video = document.createElement("video");
    const url = URL.createObjectURL(file);
    video.preload = "metadata";
    video.muted = true;
    video.playsInline = true;
    video.src = url;

    video.onloadedmetadata = () => {
      const duration = Math.round(video.duration);
      const seekTime = Math.min(1, video.duration * 0.25);
      video.currentTime = seekTime;
    };

    video.onseeked = () => {
      try {
        const canvas = document.createElement("canvas");
        canvas.width = Math.min(video.videoWidth, 400);
        canvas.height = Math.round((canvas.width / video.videoWidth) * video.videoHeight);
        const ctx = canvas.getContext("2d");
        if (ctx) {
          ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
          canvas.toBlob((blob) => {
            URL.revokeObjectURL(url);
            resolve({ thumbnail: blob, duration: Math.round(video.duration) });
          }, "image/jpeg", 0.8);
        } else {
          URL.revokeObjectURL(url);
          resolve({ thumbnail: null, duration: Math.round(video.duration) });
        }
      } catch {
        URL.revokeObjectURL(url);
        resolve({ thumbnail: null, duration: Math.round(video.duration) });
      }
    };

    video.onerror = () => {
      URL.revokeObjectURL(url);
      resolve({ thumbnail: null, duration: 0 });
    };
  });
}

function extractImageThumbnail(file: File): Promise<Blob | null> {
  return new Promise((resolve) => {
    const img = new Image();
    const url = URL.createObjectURL(file);
    img.onload = () => {
      try {
        const maxSize = 200;
        let w = img.width;
        let h = img.height;
        if (w > maxSize || h > maxSize) {
          if (w > h) {
            h = Math.round((maxSize / w) * h);
            w = maxSize;
          } else {
            w = Math.round((maxSize / h) * w);
            h = maxSize;
          }
        }
        const canvas = document.createElement("canvas");
        canvas.width = w;
        canvas.height = h;
        const ctx = canvas.getContext("2d");
        if (ctx) {
          ctx.drawImage(img, 0, 0, w, h);
          canvas.toBlob((blob) => {
            URL.revokeObjectURL(url);
            resolve(blob);
          }, "image/jpeg", 0.8);
        } else {
          URL.revokeObjectURL(url);
          resolve(null);
        }
      } catch {
        URL.revokeObjectURL(url);
        resolve(null);
      }
    };
    img.onerror = () => {
      URL.revokeObjectURL(url);
      resolve(null);
    };
    img.src = url;
  });
}

async function uploadBlobAsFile(blob: Blob, filename: string): Promise<string | null> {
  try {
    const response = await fetch("/api/uploads/request-url", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        name: filename,
        size: blob.size,
        contentType: blob.type || "image/jpeg",
      }),
    });
    if (!response.ok) return null;
    const data = await response.json();

    const putRes = await fetch(data.uploadURL, {
      method: "PUT",
      body: blob,
      headers: { "Content-Type": blob.type || "image/jpeg" },
    });
    if (!putRes.ok) return null;
    return data.objectPath;
  } catch {
    return null;
  }
}

export function UploadDialog({ children }: { children: React.ReactNode }) {
  const [open, setOpen] = useState(false);
  const [queue, setQueue] = useState<QueuedFile[]>([]);
  const [description, setDescription] = useState("");
  const [label, setLabel] = useState("");
  const [tagInput, setTagInput] = useState("");
  const soundFeedback = useSoundFeedback();
  const [tags, setTags] = useState<string[]>([]);
  const [fileDate, setFileDate] = useState<string>("");
  const [artist, setArtist] = useState("");
  const [venue, setVenue] = useState("");
  const [tour, setTour] = useState("");
  const [showEventDetails, setShowEventDetails] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [uploadComplete, setUploadComplete] = useState(false);
  const [completedCount, setCompletedCount] = useState(0);
  const [errorCount, setErrorCount] = useState(0);
  const [isAutoTagging, setIsAutoTagging] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const cancelledRef = useRef(false);

  const createMedia = useCreateMedia();
  const { uploadFile, cancelUpload } = useUpload();
  const { toast } = useToast();

  const isSingleFile = queue.length === 1;
  const hasFiles = queue.length > 0;

  const handleFileSelect = useCallback(async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files || e.target.files.length === 0) return;
    const files = Array.from(e.target.files);

    const spotsLeft = MAX_BATCH_SIZE - queue.length;
    if (spotsLeft <= 0) {
      toast({
        title: "Batch Limit Reached",
        description: `You can upload up to ${MAX_BATCH_SIZE} files at a time. Please upload your current batch first, then add more.`,
        variant: "destructive",
      });
      if (e.target) e.target.value = "";
      return;
    }

    let filesToAdd = files;
    if (files.length > spotsLeft) {
      filesToAdd = files.slice(0, spotsLeft);
      toast({
        title: "Some Files Skipped",
        description: `Only ${spotsLeft} more file${spotsLeft !== 1 ? "s" : ""} can be added (max ${MAX_BATCH_SIZE} per batch). ${files.length - spotsLeft} file${files.length - spotsLeft !== 1 ? "s" : ""} were not added.`,
      });
    }

    const newItems: QueuedFile[] = filesToAdd.map((file) => ({
      id: `${file.name}-${file.size}-${Date.now()}-${Math.random()}`,
      file,
      category: detectCategory(file.type),
      status: "pending" as FileStatus,
      progress: 0,
      title: file.name.replace(/\.[^/.]+$/, ""),
    }));

    setQueue((prev) => [...prev, ...newItems]);
    setUploadComplete(false);

    if (!fileDate && filesToAdd[0]?.lastModified) {
      const d = new Date(filesToAdd[0].lastModified);
      setFileDate(d.toISOString().split("T")[0]);
    }

    if (e.target) e.target.value = "";
  }, [fileDate, queue.length, toast]);

  const removeFromQueue = useCallback((id: string) => {
    setQueue((prev) => prev.filter((f) => f.id !== id));
  }, []);

  const updateQueueItem = useCallback((id: string, updates: Partial<QueuedFile>) => {
    setQueue((prev) => prev.map((f) => (f.id === id ? { ...f, ...updates } : f)));
  }, []);

  const handleAddTag = () => {
    const trimmed = tagInput.trim();
    if (trimmed && !tags.includes(trimmed)) {
      setTags([...tags, trimmed]);
      setTagInput("");
    }
  };

  const handleRemoveTag = (tag: string) => {
    setTags(tags.filter((t) => t !== tag));
  };

  const handleTagKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === "Enter" || e.key === ",") {
      e.preventDefault();
      handleAddTag();
    }
  };

  const handleAutoTag = async () => {
    if (queue.length === 0) return;

    const file = queue[0].file;
    const category = queue[0].category;

    setIsAutoTagging(true);
    try {
      let imageUrl: string | undefined;

      // For images, convert to base64 data URL
      if (category === "image") {
        imageUrl = await new Promise<string>((resolve, reject) => {
          const reader = new FileReader();
          reader.onload = () => {
            resolve(reader.result as string);
          };
          reader.onerror = () => {
            reject(new Error("Failed to read file"));
          };
          reader.readAsDataURL(file);
        });
      }

      const response = await fetch("/api/ai/auto-tag", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          imageUrl: imageUrl,
          filename: file.name,
          category: category,
        }),
      });

      if (!response.ok) {
        throw new Error("Failed to generate tags");
      }

      const data = await response.json();

      // Merge tags (avoid duplicates)
      if (data.tags && Array.isArray(data.tags)) {
        const newTags = data.tags.filter((tag: string) => !tags.includes(tag));
        setTags([...tags, ...newTags]);
      }

      // Set description if empty
      if (!description && data.description) {
        setDescription(data.description);
      }

      toast({
        title: "Tags Generated",
        description: "AI-generated tags and description added successfully.",
      });
    } catch (err) {
      const msg = err instanceof Error ? err.message : "Failed to generate tags";
      toast({
        title: "Error",
        description: msg,
        variant: "destructive",
      });
    } finally {
      setIsAutoTagging(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (queue.length === 0) return;

    setIsProcessing(true);
    cancelledRef.current = false;
    let completed = 0;
    let errors = 0;

    for (const item of queue) {
      if (cancelledRef.current) break;

      if (item.status === "complete") {
        completed++;
        continue;
      }

      updateQueueItem(item.id, { status: "extracting", progress: 5 });

      let thumbnailUrl: string | undefined;
      let durationSeconds: number | undefined;

      try {
        if (item.category === "video") {
          updateQueueItem(item.id, { progress: 8 });
          const meta = await extractVideoMetadata(item.file);
          durationSeconds = meta.duration || undefined;

          if (meta.thumbnail) {
            updateQueueItem(item.id, { progress: 15 });
            const thumbFilename = `thumb_${item.file.name.replace(/\.[^/.]+$/, "")}.jpg`;
            const thumbPath = await uploadBlobAsFile(meta.thumbnail, thumbFilename);
            if (thumbPath) thumbnailUrl = thumbPath;
          }
        } else if (item.category === "image") {
          updateQueueItem(item.id, { progress: 8 });
          const thumbBlob = await extractImageThumbnail(item.file);
          if (thumbBlob) {
            updateQueueItem(item.id, { progress: 15 });
            const thumbFilename = `thumb_${item.file.name.replace(/\.[^/.]+$/, "")}.jpg`;
            const thumbPath = await uploadBlobAsFile(thumbBlob, thumbFilename);
            if (thumbPath) thumbnailUrl = thumbPath;
          }
        }

        if (cancelledRef.current) break;

        updateQueueItem(item.id, { status: "uploading", progress: 20 });
        const uploadResult = await uploadFile(item.file, (rawPct) => {
          if (cancelledRef.current) return;
          const mapped = 20 + Math.round(rawPct * 0.7);
          updateQueueItem(item.id, { progress: Math.min(mapped, 90) });
        });
        if (!uploadResult) throw new Error("Upload failed");

        if (cancelledRef.current) break;

        updateQueueItem(item.id, { progress: 93 });

        const titleToUse = isSingleFile
          ? (queue[0].title || item.file.name.replace(/\.[^/.]+$/, ""))
          : item.title;

        await createMedia.mutateAsync({
          title: titleToUse,
          description: description || undefined,
          url: uploadResult.objectPath,
          filename: uploadResult.metadata.name,
          contentType: uploadResult.metadata.contentType,
          size: uploadResult.metadata.size,
          label: label || undefined,
          tags: tags.length > 0 ? tags : undefined,
          fileDate: fileDate ? new Date(fileDate) : undefined,
          thumbnailUrl: thumbnailUrl || undefined,
          durationSeconds: durationSeconds || undefined,
          artist: artist || undefined,
          venue: venue || undefined,
          tour: tour || undefined,
        });

        updateQueueItem(item.id, { status: "complete", progress: 100 });
        completed++;
      } catch (err) {
        if (cancelledRef.current) break;
        const msg = err instanceof Error ? err.message : "Upload failed";
        updateQueueItem(item.id, { status: "error", error: msg, progress: 0 });
        errors++;
      }

      setCompletedCount(completed);
      setErrorCount(errors);
    }

    if (cancelledRef.current) return;

    setIsProcessing(false);
    setUploadComplete(true);

    if (errors === 0) {
      soundFeedback("success");
      toast({
        title: "Upload Complete",
        description: `${completed} file${completed !== 1 ? "s" : ""} uploaded successfully.`,
      });
      setTimeout(() => {
        setOpen(false);
        resetForm();
      }, 1500);
    } else {
      toast({
        title: "Upload Finished",
        description: `${completed} succeeded, ${errors} failed.`,
        variant: "destructive",
      });
    }
  };

  const resetForm = () => {
    setQueue([]);
    setDescription("");
    setLabel("");
    setTagInput("");
    setTags([]);
    setFileDate("");
    setArtist("");
    setVenue("");
    setTour("");
    setShowEventDetails(false);
    setIsProcessing(false);
    setUploadComplete(false);
    setCompletedCount(0);
    setErrorCount(0);
  };

  const isPending = isProcessing || createMedia.isPending;

  const StatusIcon = ({ status }: { status: FileStatus }) => {
    switch (status) {
      case "complete":
        return <CheckCircle className="w-4 h-4 text-green-400" />;
      case "error":
        return <AlertCircle className="w-4 h-4 text-destructive" />;
      case "uploading":
      case "extracting":
        return <Loader2 className="w-4 h-4 animate-spin text-primary" />;
      default:
        return <Clock className="w-4 h-4 text-muted-foreground" />;
    }
  };

  const statusLabel = (status: FileStatus) => {
    switch (status) {
      case "complete": return "Done";
      case "error": return "Failed";
      case "uploading": return "Uploading";
      case "extracting": return "Processing";
      default: return "Pending";
    }
  };

  return (
    <Dialog
      open={open}
      onOpenChange={(val) => {
        if (!val && isProcessing) {
          cancelledRef.current = true;
          cancelUpload();
          setIsProcessing(false);
        }
        setOpen(val);
        if (!val) resetForm();
      }}
    >
      <DialogTrigger asChild>{children}</DialogTrigger>
      <DialogContent className="sm:max-w-lg max-h-[85vh] overflow-y-auto bg-background border-white/10 text-foreground">
        <DialogHeader>
          <DialogTitle className="text-xl sm:text-2xl font-display font-bold">
            Upload to Vault
          </DialogTitle>
        </DialogHeader>

        <form onSubmit={handleSubmit} className="space-y-5 mt-2">
          <div
            className={`
              relative group border-2 border-dashed rounded-xl p-4 sm:p-6
              transition-all duration-300 ease-out cursor-pointer
              ${hasFiles
                ? "border-primary/50 bg-primary/5"
                : "border-white/10"
              }
            `}
          >
            <input
              ref={fileInputRef}
              type="file"
              accept={ALL_ACCEPT}
              multiple
              onChange={handleFileSelect}
              className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
              disabled={isPending}
              data-testid="input-file"
            />
            <div className="flex flex-col items-center justify-center text-center space-y-2">
              <div
                className={`p-3 rounded-full transition-colors duration-300 ${
                  hasFiles
                    ? "bg-primary/20 text-primary"
                    : "bg-white/5 text-muted-foreground"
                }`}
              >
                {hasFiles ? (
                  <CheckCircle className="w-7 h-7" />
                ) : (
                  <UploadCloud className="w-7 h-7" />
                )}
              </div>
              <div className="space-y-1">
                <p className="font-medium text-sm">
                  {hasFiles
                    ? `${queue.length} / ${MAX_BATCH_SIZE} files selected`
                    : "Tap to select files"}
                </p>
                <p className="text-xs text-muted-foreground">
                  {hasFiles
                    ? queue.length >= MAX_BATCH_SIZE
                      ? "Batch full — upload these first, then add more"
                      : "Tap again to add more files"
                    : `Up to ${MAX_BATCH_SIZE} files per batch`}
                </p>
              </div>
            </div>
          </div>

          <AnimatePresence>
            {queue.length > 1 && (
              <motion.div
                initial={{ opacity: 0, height: 0 }}
                animate={{ opacity: 1, height: "auto" }}
                exit={{ opacity: 0, height: 0 }}
                className="space-y-2"
              >
                <Label className="text-xs font-medium uppercase tracking-wider text-muted-foreground">
                  File Queue
                </Label>
                <div className="space-y-1.5 max-h-[200px] overflow-y-auto rounded-lg">
                  {queue.map((item) => {
                    const CatIcon = CATEGORY_CONFIG[item.category].icon;
                    const catColor = CATEGORY_CONFIG[item.category].color;
                    return (
                      <motion.div
                        key={item.id}
                        initial={{ opacity: 0, x: -10 }}
                        animate={{ opacity: 1, x: 0 }}
                        exit={{ opacity: 0, x: 10 }}
                        className="flex items-center gap-2 p-2 rounded-lg bg-white/5"
                        data-testid={`queue-item-${item.id}`}
                      >
                        <CatIcon className={`w-4 h-4 shrink-0 ${catColor}`} />
                        <div className="flex-1 min-w-0">
                          <p className="text-xs font-medium truncate">{item.file.name}</p>
                          <div className="flex items-center gap-2 mt-0.5">
                            <span className="text-[10px] text-muted-foreground">
                              {formatFileSize(item.file.size)}
                            </span>
                            <span className={`text-[10px] font-medium ${
                              item.status === "complete" ? "text-green-400" :
                              item.status === "error" ? "text-destructive" :
                              item.status === "uploading" || item.status === "extracting" ? "text-primary" :
                              "text-muted-foreground"
                            }`}>
                              {item.status === "uploading" || item.status === "extracting"
                                ? `${statusLabel(item.status)} ${item.progress}%`
                                : statusLabel(item.status)}
                            </span>
                          </div>
                          {(item.status === "uploading" || item.status === "extracting") && (
                            <div className="h-1.5 bg-white/10 rounded-full overflow-hidden mt-1">
                              <motion.div
                                className="h-full bg-gradient-to-r from-primary to-primary/80 rounded-full"
                                initial={{ width: 0 }}
                                animate={{ width: `${item.progress}%` }}
                                transition={{ duration: 0.4, ease: "easeOut" }}
                              />
                            </div>
                          )}
                          {item.status === "complete" && (
                            <div className="h-1.5 bg-green-500/20 rounded-full overflow-hidden mt-1">
                              <motion.div
                                className="h-full bg-gradient-to-r from-green-500 to-emerald-400 rounded-full"
                                initial={{ width: 0 }}
                                animate={{ width: "100%" }}
                                transition={{ duration: 0.5, ease: "easeOut" }}
                              />
                            </div>
                          )}
                        </div>
                        <StatusIcon status={item.status} />
                        {item.status === "pending" && !isPending && (
                          <button
                            type="button"
                            onClick={() => removeFromQueue(item.id)}
                            className="p-0.5 rounded-full"
                            data-testid={`button-remove-${item.id}`}
                          >
                            <X className="w-3.5 h-3.5 text-muted-foreground" />
                          </button>
                        )}
                      </motion.div>
                    );
                  })}
                </div>
              </motion.div>
            )}
          </AnimatePresence>

          {isSingleFile && (
            <div className="space-y-2">
              <Label htmlFor="title" className="text-xs font-medium uppercase tracking-wider text-muted-foreground">
                Title
              </Label>
              <Input
                id="title"
                data-testid="input-title"
                value={queue[0]?.title || ""}
                onChange={(e) => updateQueueItem(queue[0].id, { title: e.target.value })}
                placeholder="Name this file"
                className="bg-white/5 border-white/10 focus:border-primary/50"
                disabled={isPending}
                required
              />
            </div>
          )}

          {isSingleFile && (
            <AnimatePresence>
              {(queue[0]?.status === "uploading" || queue[0]?.status === "extracting") && (
                <motion.div
                  initial={{ opacity: 0, height: 0 }}
                  animate={{ opacity: 1, height: "auto" }}
                  exit={{ opacity: 0, height: 0 }}
                  className="space-y-2"
                >
                  <div className="flex justify-between text-xs text-muted-foreground">
                    <span>{queue[0].status === "extracting" ? "Processing..." : "Uploading..."}</span>
                    <span>{Math.round(queue[0].progress)}%</span>
                  </div>
                  <div className="h-1.5 bg-white/10 rounded-full overflow-hidden">
                    <motion.div
                      className="h-full bg-primary rounded-full"
                      initial={{ width: 0 }}
                      animate={{ width: `${queue[0].progress}%` }}
                    />
                  </div>
                </motion.div>
              )}
            </AnimatePresence>
          )}

