                data-testid="upload-overall-progress"
              >
                <div className="flex items-center justify-between text-xs">
                  <span className="text-muted-foreground font-medium">Overall Progress</span>
                  <span className="text-primary font-semibold">
                    {completedCount} / {queue.length} files
                  </span>
                </div>
                <div className="h-2 bg-white/10 rounded-full overflow-hidden">
                  <motion.div
                    className="h-full bg-gradient-to-r from-primary via-primary/90 to-primary/70 rounded-full"
                    initial={{ width: 0 }}
                    animate={{ width: `${queue.length > 0 ? (completedCount / queue.length) * 100 : 0}%` }}
                    transition={{ duration: 0.5, ease: "easeOut" }}
                  />
                </div>
              </motion.div>
            )}
          </AnimatePresence>

          <AnimatePresence>
            {uploadComplete && (
              <motion.div
                initial={{ opacity: 0, scale: 0.95 }}
                animate={{ opacity: 1, scale: 1 }}
                exit={{ opacity: 0, scale: 0.95 }}
                className="p-3 rounded-lg bg-green-500/10 border border-green-500/20 text-sm"
                data-testid="upload-summary"
              >
                <div className="flex items-center gap-2">
                  <motion.div
                    initial={{ scale: 0 }}
                    animate={{ scale: 1 }}
                    transition={{ type: "spring", stiffness: 400, damping: 15 }}
                  >
                    <CheckCircle className="w-5 h-5 text-green-400 shrink-0" />
                  </motion.div>
                  <span className="font-medium">
                    {completedCount} file{completedCount !== 1 ? "s" : ""} uploaded successfully
                    {errorCount > 0 && <span className="text-destructive"> ({errorCount} failed)</span>}
                  </span>
                </div>
              </motion.div>
            )}
          </AnimatePresence>

          <div className="flex gap-3 justify-end pt-1">
            {isProcessing ? (
              <Button
                type="button"
                variant="destructive"
                onClick={() => {
                  cancelledRef.current = true;
                  cancelUpload();
                  setIsProcessing(false);
                  setOpen(false);
                  resetForm();
                }}
                data-testid="button-cancel-upload"
              >
                <X className="w-4 h-4 mr-1" />
                Cancel Upload
              </Button>
            ) : (
              <Button
                type="button"
                variant="ghost"
                onClick={() => setOpen(false)}
                data-testid="button-cancel"
              >
                Cancel
              </Button>
            )}
            <Button
              type="submit"
              data-testid="button-upload-submit"
              disabled={
                !hasFiles ||
                (isSingleFile && !queue[0]?.title) ||
                isPending ||
                uploadComplete
              }
              className="bg-primary text-white min-w-[100px]"
            >
              {isPending ? (
                <Loader2 className="h-4 w-4 animate-spin" />
              ) : (
                `Upload${queue.length > 1 ? ` (${queue.length})` : ""}`
              )}
            </Button>
          </div>
        </form>
      </DialogContent>
    </Dialog>
  );
}

