function getGreeting(): string {
  const now = new Date();
  const centralHour = parseInt(
    new Intl.DateTimeFormat("en-US", {
      hour: "numeric",
      hour12: false,
      timeZone: "America/Chicago",
    }).format(now),
    10
  );

  if (centralHour >= 5 && centralHour < 12) return "Good morning";
  if (centralHour >= 12 && centralHour < 17) return "Good afternoon";
  return "Good evening";
}

const FILTER_TABS: { key: string; label: string; icon: any }[] = [
  { key: "all", label: "All", icon: LayoutGrid },
  { key: "video", label: "Video", icon: Film },
  { key: "audio", label: "Audio", icon: Music },
  { key: "image", label: "Images", icon: ImageIcon },
  { key: "document", label: "Docs", icon: FileText },
  { key: "favorites", label: "Favorites", icon: Heart },
  { key: "shared", label: "Shared with me", icon: Share2 },
];

type SortOption = "date-desc" | "date-asc" | "name-asc" | "name-desc" | "size-desc" | "size-asc";
type ViewMode = "grid" | "timeline";

const SORT_OPTIONS: { value: SortOption; label: string }[] = [
  { value: "date-desc", label: "Date (newest first)" },
  { value: "date-asc", label: "Date (oldest first)" },
  { value: "name-asc", label: "Name (A-Z)" },
  { value: "name-desc", label: "Name (Z-A)" },
  { value: "size-desc", label: "Size (largest)" },
  { value: "size-asc", label: "Size (smallest)" },
];

function getItemDate(item: MediaResponse): Date {
  if (item.fileDate) return new Date(item.fileDate);
  if (item.createdAt) return new Date(item.createdAt);
  return new Date(0);
}

function sortItems(items: MediaResponse[], sort: SortOption): MediaResponse[] {
  const sorted = [...items];
  sorted.sort((a, b) => {
    switch (sort) {
      case "date-desc":
        return getItemDate(b).getTime() - getItemDate(a).getTime();
      case "date-asc":
        return getItemDate(a).getTime() - getItemDate(b).getTime();
      case "name-asc":
        return a.title.localeCompare(b.title);
      case "name-desc":
        return b.title.localeCompare(a.title);
      case "size-desc":
        return (b.size || 0) - (a.size || 0);
      case "size-asc":
        return (a.size || 0) - (b.size || 0);
      default:
        return 0;
    }
  });
  return sorted;
}

function groupByYearMonth(items: MediaResponse[]): Map<string, Map<string, MediaResponse[]>> {
  const years = new Map<string, Map<string, MediaResponse[]>>();
  items.forEach(item => {
    const date = getItemDate(item);
    const year = format(date, "yyyy");
    const month = format(date, "MMMM");
    if (!years.has(year)) years.set(year, new Map());
    const monthMap = years.get(year)!;
    if (!monthMap.has(month)) monthMap.set(month, []);
    monthMap.get(month)!.push(item);
  });
  return years;
}

function TimelineView({
  items,
  onPlay,
  onEdit,
  bulkMode,
  selectedIds,
  onToggleSelect,
}: {
  items: MediaResponse[];
  onPlay: (item: MediaResponse) => void;
  onEdit: (item: MediaResponse) => void;
  bulkMode: boolean;
  selectedIds: Set<number>;
  onToggleSelect: (id: number) => void;
}) {
  const grouped = useMemo(() => groupByYearMonth(items), [items]);
  const [collapsed, setCollapsed] = useState<Set<string>>(new Set());

  const toggleSection = (key: string) => {
    setCollapsed(prev => {
      const next = new Set(prev);
      if (next.has(key)) next.delete(key);
      else next.add(key);
      return next;
    });
  };

  if (items.length === 0) {
    return (
      <MediaGrid items={items} onPlay={onPlay} onEdit={onEdit} />
    );
  }

  const sortedYears = Array.from(grouped.keys()).sort((a, b) => Number(b) - Number(a));

  return (
    <div className="space-y-6">
      {sortedYears.map(year => {
        const months = grouped.get(year)!;
        const monthNames = [
          "December", "November", "October", "September", "August", "July",
          "June", "May", "April", "March", "February", "January",
        ];
        const sortedMonths = Array.from(months.keys()).sort(
          (a, b) => monthNames.indexOf(a) - monthNames.indexOf(b)
        );

        return (
          <div key={year} className="space-y-3">
            <h3 className="text-lg font-display font-bold text-foreground" data-testid={`text-timeline-year-${year}`}>
              {year}
            </h3>
            {sortedMonths.map(month => {
              const sectionKey = `${year}-${month}`;
              const monthItems = months.get(month)!;
              const isCollapsed = collapsed.has(sectionKey);

              return (
                <div key={sectionKey} className="glass-card rounded-xl overflow-visible">
                  <button
                    onClick={() => toggleSection(sectionKey)}
                    className="w-full flex items-center gap-2 px-4 py-3 text-left"
                    data-testid={`button-timeline-toggle-${sectionKey}`}
                  >
                    {isCollapsed ? (
                      <ChevronRight className="w-4 h-4 text-muted-foreground shrink-0" />
                    ) : (
                      <ChevronDown className="w-4 h-4 text-muted-foreground shrink-0" />
                    )}
                    <span className="font-medium text-foreground">{month}</span>
                    <Badge variant="secondary" className="no-default-hover-elevate no-default-active-elevate text-xs">
                      {monthItems.length}
                    </Badge>
                  </button>
                  {!isCollapsed && (
                    <div className="px-4 pb-4">
                      {bulkMode ? (
                        <BulkMediaGrid
                          items={monthItems}
                          onPlay={onPlay}
                          onEdit={onEdit}
                          selectedIds={selectedIds}
                          onToggleSelect={onToggleSelect}
                        />
                      ) : (
                        <MediaGrid items={monthItems} onPlay={onPlay} onEdit={onEdit} />
                      )}
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        );
      })}
    </div>
  );
}

function BulkMediaGrid({
  items,
  onPlay,
  onEdit,
  selectedIds,
  onToggleSelect,
}: {
  items: MediaResponse[];
  onPlay: (item: MediaResponse) => void;
  onEdit: (item: MediaResponse) => void;
  selectedIds: Set<number>;
  onToggleSelect: (id: number) => void;
}) {
  return (
    <div className="grid grid-cols-2 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-3 sm:gap-5">
      {items.map(item => {
        const isSelected = selectedIds.has(item.id);
        return (
          <div key={item.id} className="relative">
            <div
              className="absolute top-2 left-2 z-20 cursor-pointer"
              onClick={(e) => {
                e.stopPropagation();
                onToggleSelect(item.id);
              }}
              data-testid={`checkbox-select-${item.id}`}
            >
              {isSelected ? (
                <CheckSquare className="w-5 h-5 text-primary" />
              ) : (
                <Square className="w-5 h-5 text-muted-foreground" />
              )}
            </div>
            <div className={`transition-opacity ${isSelected ? "ring-2 ring-primary rounded-xl" : ""}`}>
              <MediaGrid
                items={[item]}
                onPlay={onPlay}
                onEdit={onEdit}
              />
            </div>
          </div>
        );
      })}
    </div>
  );
}

function CollectionCard({
  collection,
  isActive,
  onClick,
  onShare,
  draggable,
  onDragStart,
  onDragOver,
  onDragEnd,
  onDrop,
  isDragOver,
}: {
  collection: CollectionWithCount;
  isActive: boolean;
  onClick: () => void;
  onShare?: () => void;
  draggable?: boolean;
  onDragStart?: (e: React.DragEvent) => void;
  onDragOver?: (e: React.DragEvent) => void;
  onDragEnd?: (e: React.DragEvent) => void;
  onDrop?: (e: React.DragEvent) => void;
  isDragOver?: boolean;
}) {
  return (
    <div
      className={`relative group shrink-0 transition-transform duration-200 ${isDragOver ? "scale-105 opacity-70" : ""}`}
      draggable={draggable}
      onDragStart={onDragStart}
      onDragOver={onDragOver}
      onDragEnd={onDragEnd}
      onDrop={onDrop}
    >
      <button
        onClick={onClick}
        className={`
          flex flex-col items-center gap-3 p-3.5 rounded-xl transition-all min-w-[130px] card-glow
          ${isActive
            ? "ring-2 ring-primary/50 bg-primary/10"
            : ""
          }
        `}
        data-testid={`button-collection-${collection.id}`}
      >
        <div className="w-16 h-16 rounded-xl premium-gradient-collection flex items-center justify-center overflow-hidden shadow-lg">
          {collection.coverUrl ? (
            <img src={`/objects/${collection.coverUrl}`} alt="" className="w-full h-full object-cover" />
          ) : (
            <FolderOpen className="w-7 h-7 text-white drop-shadow-lg" />
          )}
        </div>
        <div className="text-center">
          <p className="text-xs font-semibold text-foreground truncate max-w-[110px]" data-testid={`text-collection-name-${collection.id}`}>
            {collection.name}
          </p>
          <div className="flex items-center gap-1 justify-center mt-1">
            <Badge variant="secondary" className="no-default-hover-elevate no-default-active-elevate text-[10px]">
              {collection.itemCount}
            </Badge>
            {(collection as any).isShared && (
              <Users className="w-3 h-3 text-primary/70" />
            )}
          </div>
        </div>
      </button>
      {onShare && (
        <button
          onClick={(e) => { e.stopPropagation(); onShare(); }}
          className="absolute top-2 right-2 w-6 h-6 rounded-full bg-white/10 flex items-center justify-center invisible group-hover:visible transition-all"
          data-testid={`button-share-collection-${collection.id}`}
        >
          <Share2 className="w-3 h-3 text-muted-foreground" />
        </button>
      )}
    </div>
  );
}

function NewCollectionDialog({
  open,
  onOpenChange,
  collections = [],
}: {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  collections?: CollectionWithCount[];
}) {
  const [name, setName] = useState("");
  const [description, setDescription] = useState("");
  const [parentId, setParentId] = useState<string>("none");
  const createCollection = useCreateCollection();
  const { toast } = useToast();

  const handleCreate = async () => {
    if (!name.trim()) return;
    try {
      await createCollection.mutateAsync({
        name: name.trim(),
        description: description.trim() || undefined,
        parentId: parentId !== "none" ? parseInt(parentId) : undefined,
      });
      toast({ title: "Collection created", description: `"${name}" has been created.` });
      setName("");
      setDescription("");
      setParentId("none");
      onOpenChange(false);
    } catch {
      toast({ title: "Error", description: "Failed to create collection.", variant: "destructive" });
    }
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-md bg-background border-white/10 text-foreground">
        <DialogHeader>
          <DialogTitle className="text-xl font-display font-bold">New Collection</DialogTitle>
        </DialogHeader>
        <div className="space-y-4 mt-2">
          <div className="space-y-2">
            <Label htmlFor="collection-name" className="text-xs font-medium uppercase tracking-wider text-muted-foreground">Name</Label>
            <Input
              id="collection-name"
              data-testid="input-collection-name"
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="My Collection"
              className="bg-white/5 border-white/10 focus:border-primary/50"
            />
          </div>
          <div className="space-y-2">
            <Label htmlFor="collection-description" className="text-xs font-medium uppercase tracking-wider text-muted-foreground">Description</Label>
            <Input
              id="collection-description"
              data-testid="input-collection-description"
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              placeholder="Optional description"
              className="bg-white/5 border-white/10 focus:border-primary/50"
            />
          </div>
          {collections.length > 0 && (
            <div className="space-y-2">
              <Label className="text-xs font-medium uppercase tracking-wider text-muted-foreground">Parent Folder</Label>
              <Select value={parentId} onValueChange={setParentId}>
                <SelectTrigger className="bg-white/5 border-white/10" data-testid="select-parent-collection">
                  <SelectValue placeholder="None (root level)" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="none">None (root level)</SelectItem>
                  {collections.map(col => (
                    <SelectItem key={col.id} value={String(col.id)}>
                      {col.name}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
          )}
          <Button
            data-testid="button-create-collection"
            onClick={handleCreate}
            disabled={!name.trim() || createCollection.isPending}
            className="w-full bg-primary text-white"
          >
            {createCollection.isPending ? <Loader2 className="w-4 h-4 animate-spin" /> : "Create Collection"}
          </Button>
        </div>
      </DialogContent>
    </Dialog>
  );
}

function ShareCollectionDialog({
  open,
  onOpenChange,
  collection,
}: {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  collection: CollectionWithCount | null;
}) {
  const [selectedTenants, setSelectedTenants] = useState<Set<string>>(new Set());
  const shareCollection = useShareCollection();
  const { toast } = useToast();

  const { data: familyMembers } = useQuery({
    queryKey: ["/api/family-members"],
    queryFn: async () => {
      const res = await fetch("/api/family-members", { credentials: "include" });
      if (!res.ok) return [];
      return res.json() as Promise<{ id: string; name: string }[]>;
    },
    enabled: open,
  });

  const toggleTenant = (tenantId: string) => {
    setSelectedTenants(prev => {
      const next = new Set(prev);
      if (next.has(tenantId)) next.delete(tenantId);
      else next.add(tenantId);
      return next;
    });
  };

  const handleShare = async () => {
    if (!collection || selectedTenants.size === 0) return;
    try {
      await shareCollection.mutateAsync({
        collectionId: collection.id,
        tenantIds: Array.from(selectedTenants),
      });
      toast({ title: "Collection shared", description: `Shared "${collection.name}" with ${selectedTenants.size} family member(s).` });
      setSelectedTenants(new Set());
      onOpenChange(false);
    } catch {
      toast({ title: "Error", description: "Failed to share collection.", variant: "destructive" });
    }
  };

  const members = familyMembers || [];

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-md bg-background border-white/10 text-foreground">
        <DialogHeader>
          <DialogTitle className="text-xl font-display font-bold flex items-center gap-2">
            <Share2 className="w-5 h-5 text-primary" />
            Share Collection
          </DialogTitle>
        </DialogHeader>
        {collection && (
          <div className="space-y-4 mt-2">
            <p className="text-sm text-muted-foreground">
              Share <span className="font-semibold text-foreground">"{collection.name}"</span> with family members
            </p>
            <div className="space-y-2">
              {members.map(member => (
                <button
                  key={member.id}
                  onClick={() => toggleTenant(member.id)}
                  className={`w-full flex items-center gap-3 p-3 rounded-lg transition-all ${
                    selectedTenants.has(member.id)
                      ? "bg-primary/15 ring-1 ring-primary/30"
                      : "bg-white/5"
                  }`}
                  data-testid={`button-share-${member.name?.toLowerCase()}`}
                >
                  <div className={`w-9 h-9 rounded-full flex items-center justify-center text-sm font-bold ${
                    selectedTenants.has(member.id)
                      ? "bg-primary text-white"
                      : "bg-white/10 text-muted-foreground"
                  }`}>
                    {member.name?.[0] || "?"}
                  </div>
                  <span className="text-sm font-medium flex-1 text-left">{member.name}</span>
                  {selectedTenants.has(member.id) && (
                    <Check className="w-4 h-4 text-primary" />
                  )}
                </button>
              ))}
              {members.length === 0 && (
                <p className="text-sm text-muted-foreground text-center py-4">No family members found</p>
              )}
            </div>
            <Button
              data-testid="button-confirm-share"
              onClick={handleShare}
              disabled={selectedTenants.size === 0 || shareCollection.isPending}
              className="w-full bg-primary text-white"
            >
              {shareCollection.isPending ? (
                <Loader2 className="w-4 h-4 animate-spin" />
              ) : (
                `Share with ${selectedTenants.size} member${selectedTenants.size !== 1 ? "s" : ""}`
              )}
            </Button>
          </div>
        )}
      </DialogContent>
    </Dialog>
  );
}

function ShareMediaDialog({
  open,
  onOpenChange,
  mediaItem,
}: {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  mediaItem: MediaResponse | null;
}) {
  const [selectedTenants, setSelectedTenants] = useState<Set<string>>(new Set());
  const [sharing, setSharing] = useState(false);
  const { toast } = useToast();

  const { data: familyMembers } = useQuery({
    queryKey: ["/api/family-members"],
    queryFn: async () => {
      const res = await fetch("/api/family-members", { credentials: "include" });
      if (!res.ok) return [];
      return res.json() as Promise<{ id: string; name: string }[]>;
    },
    enabled: open,
  });

  const toggleTenant = (tenantId: string) => {
    setSelectedTenants(prev => {
      const next = new Set(prev);
      if (next.has(tenantId)) next.delete(tenantId);
      else next.add(tenantId);
      return next;
    });
  };

  const handleShare = async () => {
    if (!mediaItem || selectedTenants.size === 0) return;
    setSharing(true);
    try {
      const res = await fetch(`/api/media/${mediaItem.id}/share`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        credentials: "include",
        body: JSON.stringify({ sharedWithTenantIds: Array.from(selectedTenants) }),
