                data-testid="input-search-mobile"
                placeholder={aiSearchMode ? "Ask AI to find..." : "Search files..."}
                className="pl-9 bg-white/5 border-white/10 rounded-full h-10"
                value={searchQuery}
                onChange={(e) => handleAiSearchInputChange(e.target.value)}
                onKeyDown={handleSearchKeyDown}
              />
            </div>
          </div>
          {aiSearchMode && aiSearchResults !== null && (
            <div className="flex items-center gap-2 px-1">
              <Badge variant="secondary" className="no-default-hover-elevate no-default-active-elevate gap-1">
                <Sparkles className="w-3 h-3" />
                AI found {aiSearchResults.length} item{aiSearchResults.length !== 1 ? "s" : ""}
              </Badge>
              <Button
                variant="ghost"
                size="icon"
                onClick={() => { setAiSearchResults(null); setSearchQuery(""); }}
                data-testid="button-clear-ai-results-mobile"
              >
                <X className="w-3.5 h-3.5" />
              </Button>
            </div>
          )}
        </div>

        {!activeCollectionId && (
          <motion.div
            initial={{ opacity: 0, y: 12 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.4, delay: 0.1 }}
            className="flex gap-2.5 mb-6 overflow-x-auto pb-1 scrollbar-hide -mx-4 px-4 sm:mx-0 sm:px-0"
          >
            {FILTER_TABS.map(tab => {
              const isActive = activeFilter === tab.key;
              const count = categoryCounts[tab.key] || 0;
              const Icon = tab.icon;
              return (
                <button
                  key={tab.key}
                  onClick={() => setActiveFilter(tab.key)}
                  className={`
                    flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-semibold
                    whitespace-nowrap transition-all duration-300 shrink-0
                    ${isActive
                      ? "bg-primary text-white shadow-lg shadow-primary/30 scale-[1.02]"
                      : "bg-white/5 text-muted-foreground border border-white/8 hover-elevate active-elevate-2 backdrop-blur-sm"
                    }
                  `}
                  data-testid={`button-filter-${tab.key}`}
                >
                  <Icon className="w-4 h-4" />
                  {tab.label}
                  {count > 0 && (
                    <span className={`text-[10px] px-1.5 py-0.5 rounded-full font-bold ${isActive ? "bg-white/20" : "bg-white/10"}`}>
                      {count}
                    </span>
                  )}
                </button>
              );
            })}
          </motion.div>
        )}

        <motion.div
          initial={{ opacity: 0, y: 12 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.4, delay: 0.15 }}
          className="flex gap-2 mb-6 overflow-x-auto pb-1 scrollbar-hide -mx-4 px-4 sm:mx-0 sm:px-0"
        >
          {(() => {
            const rootCollections = collections.filter(c => !(c as any).parentId);
            const childCollections = activeCollectionId
              ? collections.filter(c => (c as any).parentId === activeCollectionId)
              : [];
            const displayCollections = activeCollectionId ? childCollections : rootCollections;

            return (
              <>
                {displayCollections.map(col => (
                  <CollectionCard
                    key={col.id}
                    collection={col}
                    isActive={activeCollectionId === col.id}
                    onClick={() => setActiveCollectionId(activeCollectionId === col.id ? null : col.id)}
                    onShare={() => setSharingCollection(col)}
                    draggable
                    isDragOver={dragOverCollectionId === col.id}
                    onDragStart={(e) => {
                      dragCollectionId.current = col.id;
                      e.dataTransfer.effectAllowed = "move";
                    }}
                    onDragOver={(e) => {
                      e.preventDefault();
                      e.dataTransfer.dropEffect = "move";
                      if (dragCollectionId.current !== col.id) {
                        setDragOverCollectionId(col.id);
                      }
                    }}
                    onDrop={(e) => {
                      e.preventDefault();
                      setDragOverCollectionId(null);
                      const fromId = dragCollectionId.current;
                      if (fromId === null || fromId === col.id) return;
                      const ids = displayCollections.map(c => c.id);
                      const fromIdx = ids.indexOf(fromId);
                      const toIdx = ids.indexOf(col.id);
                      if (fromIdx === -1 || toIdx === -1) return;
                      ids.splice(fromIdx, 1);
                      ids.splice(toIdx, 0, fromId);
                      reorderCollections.mutate(ids);
                    }}
                    onDragEnd={() => {
                      dragCollectionId.current = null;
                      setDragOverCollectionId(null);
                    }}
                  />
                ))}
                {displayCollections.length === 0 && !activeCollectionId && collections.length === 0 && null}
              </>
            );
          })()}
          <button
            onClick={() => setShowNewCollectionDialog(true)}
            className="shrink-0 flex flex-col items-center gap-3 p-3.5 rounded-xl min-w-[130px] card-glow"
            data-testid="button-new-collection"
          >
            <div className="w-16 h-16 rounded-xl bg-gradient-to-br from-white/5 to-white/10 flex items-center justify-center border border-dashed border-white/20 shadow-lg">
              <FolderPlus className="w-7 h-7 text-muted-foreground" />
            </div>
            <p className="text-xs font-semibold text-muted-foreground">New Collection</p>
          </button>
        </motion.div>

        {sharedCollections.length > 0 && !activeCollectionId && (
          <div className="mb-6">
            <div className="flex items-center gap-2 mb-3">
              <Users className="w-4 h-4 text-primary/70" />
              <span className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">Shared with you</span>
            </div>
            <div className="flex gap-2 overflow-x-auto pb-1 scrollbar-hide -mx-4 px-4 sm:mx-0 sm:px-0">
              {sharedCollections.map(col => (
                <CollectionCard
                  key={`shared-${col.id}`}
                  collection={col}
                  isActive={activeCollectionId === col.id}
                  onClick={() => setActiveCollectionId(activeCollectionId === col.id ? null : col.id)}
                />
              ))}
            </div>
          </div>
        )}

        <div className="flex flex-col gap-3 mb-6 p-3.5 rounded-xl glass-morphism">
          <div className="flex items-center gap-2 flex-wrap">
            <div className="flex items-center rounded-lg overflow-visible bg-white/5 border border-white/10">
              <Button
                variant="ghost"
                size="sm"
                onClick={() => setViewMode("grid")}
                className={`rounded-r-none ${viewMode === "grid" ? "bg-primary/20 text-primary" : ""}`}
                data-testid="button-view-grid"
              >
                <Grid className="w-4 h-4" />
              </Button>
              <Button
                variant="ghost"
                size="sm"
                onClick={() => setViewMode("timeline")}
                className={`rounded-l-none ${viewMode === "timeline" ? "bg-primary/20 text-primary" : ""}`}
                data-testid="button-view-timeline"
              >
                <List className="w-4 h-4" />
              </Button>
            </div>

            <Select value={sortOption} onValueChange={(v) => setSortOption(v as SortOption)}>
              <SelectTrigger className="w-[140px] sm:w-[180px] bg-white/5 border-white/10" data-testid="select-sort">
                <ArrowUpDown className="w-3.5 h-3.5 mr-1.5 text-muted-foreground" />
                <SelectValue />
              </SelectTrigger>
              <SelectContent className="glass-morphism">
                {SORT_OPTIONS.map(opt => (
                  <SelectItem key={opt.value} value={opt.value} data-testid={`sort-option-${opt.value}`}>
                    {opt.label}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          <div className="flex items-center gap-2 flex-wrap">
            <CalendarRange className="w-4 h-4 text-muted-foreground shrink-0" />
            <Input
              type="date"
              value={dateFrom}
              onChange={(e) => setDateFrom(e.target.value)}
              className="w-[120px] sm:w-[140px] bg-white/5 border-white/10 text-sm"
              data-testid="input-date-from"
              placeholder="From"
            />
            <span className="text-muted-foreground text-sm">to</span>
            <Input
              type="date"
              value={dateTo}
              onChange={(e) => setDateTo(e.target.value)}
              className="w-[120px] sm:w-[140px] bg-white/5 border-white/10 text-sm"
              data-testid="input-date-to"
              placeholder="To"
            />
            {(dateFrom || dateTo) && (
              <Button
                variant="ghost"
                size="icon"
                onClick={() => { setDateFrom(""); setDateTo(""); }}
                data-testid="button-clear-dates"
              >
                <X className="w-4 h-4" />
              </Button>
            )}
          </div>
        </div>

        {mediaLoading ? (
          <div className="grid grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4 sm:gap-5">
            {[1, 2, 3, 4, 5, 6, 7, 8].map((i) => (
              <div key={i} className={`rounded-xl overflow-hidden card-glow ${i === 1 ? "col-span-2 row-span-2" : ""}`}>
                <div className={`${i === 1 ? "aspect-square" : "aspect-[4/3]"} shimmer relative`}>
                  <div className="absolute inset-0 bg-gradient-to-t from-black/40 to-transparent" />
                </div>
                <div className="p-3.5 sm:p-4 space-y-2.5 bg-gradient-to-b from-black/40 to-card/80">
                  <div className="h-4 w-3/4 rounded-md shimmer" />
                  <div className="h-3 w-1/2 rounded-md shimmer" />
                  <div className="flex gap-1.5 mt-1">
                    <div className="h-5 w-12 rounded-full shimmer" />
                    <div className="h-5 w-16 rounded-full shimmer" />
                  </div>
                </div>
              </div>
            ))}
          </div>
        ) : viewMode === "timeline" ? (
          <TimelineView
            items={filtered}
            onPlay={handlePlay}
            onEdit={setEditingItem}
            bulkMode={bulkMode}
            selectedIds={selectedIds}
            onToggleSelect={toggleSelect}
          />
        ) : bulkMode ? (
          <BulkMediaGrid
            items={filtered}
            onPlay={handlePlay}
            onEdit={setEditingItem}
            selectedIds={selectedIds}
            onToggleSelect={toggleSelect}
          />
        ) : (
          <MediaGrid
            items={filtered}
            onPlay={handlePlay}
            onEdit={setEditingItem}
            onShare={setSharingMedia}
            onAddToPlaylist={setAddToPlaylistItemId}
          />
        )}

        {!activeCollectionId && (activeFilter === "audio" || activeFilter === "all") && (
          <div className="mt-6">
            <PlaylistPanel
              onPlayTrack={(item) => {
                if (item.category === "audio") setNowPlayingItem(item);
              }}
            />
          </div>
        )}

        {!activeCollectionId && (
          <div className="mt-8">
            <ActivityFeed compact />
          </div>
        )}
      </main>

      {!bulkMode && (
        <div className="fixed bottom-4 right-4 md:hidden z-30">
          <UploadDialog>
            <Button size="icon" data-testid="button-upload-fab" className="rounded-full bg-primary text-white shadow-2xl shadow-primary/40 w-14 h-14">
              <Plus className="w-6 h-6" />
            </Button>
          </UploadDialog>
        </div>
      )}

      <AnimatePresence>
        {bulkMode && (
          <BulkActionBar
            selectedIds={selectedIds}
            allItems={filtered}
            onSelectAll={selectAll}
            onDeselectAll={deselectAll}
            onExitBulk={exitBulk}
            collections={collections}
            activeCollectionId={activeCollectionId}
          />
        )}
      </AnimatePresence>

      <MediaViewer
        item={viewingItem}
        open={!!viewingItem}
        onOpenChange={(open) => !open && setViewingItem(null)}
      />

      {nowPlayingItem && (
        <NowPlaying
          item={nowPlayingItem}
          playlist={audioPlaylist}
          open={!!nowPlayingItem}
          onClose={() => setNowPlayingItem(null)}
          onTrackChange={(track) => setNowPlayingItem(track)}
        />
      )}

      <AmbientMode
        items={mediaItems || []}
        open={showAmbientMode}
        onClose={() => setShowAmbientMode(false)}
      />

      <AddToPlaylistDialog
        open={!!addToPlaylistItemId}
        onOpenChange={(open) => !open && setAddToPlaylistItemId(null)}
        mediaItemId={addToPlaylistItemId || 0}
      />

      <VinylAgent externalOpen={showSpinny} onExternalOpenChange={setShowSpinny} />

      <EditMediaDialog
        item={editingItem}
        open={!!editingItem}
        onOpenChange={(open) => !open && setEditingItem(null)}
      />

      <NewCollectionDialog
        open={showNewCollectionDialog}
        onOpenChange={setShowNewCollectionDialog}
        collections={collections}
      />

      <ShareCollectionDialog
        open={!!sharingCollection}
        onOpenChange={(open) => { if (!open) setSharingCollection(null); }}
        collection={sharingCollection}
      />

      <ShareMediaDialog
        open={!!sharingMedia}
        onOpenChange={(open) => { if (!open) setSharingMedia(null); }}
        mediaItem={sharingMedia}
      />

      <ChangePasswordDialog
        open={showChangePassword}
        onOpenChange={setShowChangePassword}
      />

      <OnboardingGuide
        open={showOnboarding}
        onOpenChange={setShowOnboarding}
      />

    </div>
  );
}


function PasswordLogin() {
  const { login, isLoggingIn, loginError, accountCount, claimAccount, isClaimingAccount } = useAuth();
  const [, navigateAfterLogin] = useLocation();
  const [name, setName] = useState("");
  const [password, setPassword] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [shake, setShake] = useState(false);
  const [errorMsg, setErrorMsg] = useState("");
  const [rememberMe, setRememberMe] = useState(false);
  const [devMode, setDevMode] = useState(false);
  const [devPin, setDevPin] = useState("");
  const [claimMode, setClaimMode] = useState(() => {
    return typeof window !== "undefined" && new URLSearchParams(window.location.search).get("setup") === "1";
  });
  const [claimEmail, setClaimEmail] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");

  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    if (params.get("setup") === "1") {
      setClaimMode(true);
    }
  }, []);

  const multiUser = accountCount > 1;

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (claimMode) {
      if (!name.trim()) {
        setErrorMsg("Please enter your name");
        return;
      }
      if (!claimEmail.trim()) {
        setErrorMsg("Please enter your email");
        return;
      }
      if (!password) {
        setErrorMsg("Please create a password");
        return;
      }
      if (password !== confirmPassword) {
        setErrorMsg("Passwords don't match");
        return;
      }
      setErrorMsg("");
      try {
        await claimAccount({ name: name.trim(), password, email: claimEmail.trim() });
        navigateAfterLogin("/dashboard");
      } catch (err: any) {
        setShake(true);
        setTimeout(() => setShake(false), 600);
        const msg = err.message || "Account setup failed";
        setErrorMsg(msg.includes(":") ? msg.split(": ").slice(1).join(": ") : msg);
      }
      return;
    }

    if (devMode) {
      if (!devPin) return;
      setErrorMsg("");
      try {
        await login({ name: "Jason", password: devPin, rememberMe: true });
        navigateAfterLogin("/dashboard");
      } catch (err: any) {
        setShake(true);
        setTimeout(() => setShake(false), 600);
        setErrorMsg(err.message || "Invalid developer PIN.");
        setDevPin("");
      }
      return;
    }
    if (!password) return;
    if (multiUser && !name.trim()) {
      setErrorMsg("Please enter your name");
      return;
    }
    setErrorMsg("");

    try {
      await login({ name: multiUser ? name.trim() : undefined, password, rememberMe });
      navigateAfterLogin("/dashboard");
    } catch (err: any) {
      setShake(true);
      setTimeout(() => setShake(false), 600);
      setErrorMsg(err.message || "Incorrect password. Try again.");
      setPassword("");
    }
  };

  return (
    <div className="min-h-[100dvh] bg-background flex flex-col md:flex-row">
      <div className="relative w-full md:w-1/2 lg:w-3/5 h-[28vh] sm:h-[35vh] md:h-screen shrink-0 overflow-hidden bg-black">
        <div className="absolute inset-0 bg-[radial-gradient(ellipse_at_top_right,_var(--tw-gradient-stops))] from-indigo-900 via-background to-background opacity-80" />
        <motion.div
          initial={{ scale: 0.8, opacity: 0 }}
          animate={{ scale: 1, opacity: 1 }}
          transition={{ duration: 1.2, ease: "easeOut" }}
          className="absolute top-0 right-0 w-[500px] h-[500px] bg-primary/20 rounded-full blur-[120px] mix-blend-screen animate-pulse"
        />
        <motion.div
          initial={{ scale: 0.8, opacity: 0 }}
          animate={{ scale: 1, opacity: 1 }}
          transition={{ duration: 1.4, delay: 0.2, ease: "easeOut" }}
          className="absolute bottom-0 left-0 w-[400px] h-[400px] bg-purple-600/10 rounded-full blur-[100px] mix-blend-screen"
        />

        <div className="absolute inset-0 flex flex-col items-center justify-center p-6 md:p-16 z-10 bg-gradient-to-t from-black/60 via-transparent to-transparent">
          <motion.img
            initial={{ opacity: 0, scale: 0.7, y: 20 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            transition={{ duration: 0.7, delay: 0.1, ease: [0.34, 1.56, 0.64, 1] }}
            src={trustlayerEmblem}
            alt="DW Media Studio"
            className="w-20 h-20 sm:w-32 sm:h-32 md:w-44 md:h-44 object-cover mb-4 md:mb-8"
          />
          <motion.h2
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6, delay: 0.3 }}
            className="text-2xl sm:text-3xl md:text-5xl font-display font-bold text-white mb-2 md:mb-4 leading-tight text-center"
          >
            Your digital assets,<br />
            <span className="theme-gradient-text">
              secured forever.
            </span>
          </motion.h2>
          <motion.p
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ duration: 0.5, delay: 0.6 }}
            className="text-white/60 text-lg hidden md:block text-center max-w-md"
          >
            A private vault for your most valuable media and memories.
          </motion.p>
        </div>
      </div>

      <motion.div
        initial={{ opacity: 0, x: 30 }}
        animate={{ opacity: 1, x: 0 }}
        transition={{ duration: 0.6, delay: 0.4 }}
        className="w-full md:w-1/2 lg:w-2/5 flex flex-col items-center md:justify-center p-5 sm:p-8 bg-card border-l border-white/5 overflow-y-auto flex-1"
      >
        <div className="max-w-sm w-full space-y-8">
          <div className="text-center">
            <h1 className="text-2xl font-display font-bold tracking-tight mb-1" data-testid="text-login-title">
              {claimMode ? "Set Up Your Account" : devMode ? "Developer Access" : "Welcome Back"}
            </h1>
            <p className="text-sm text-muted-foreground">
              {claimMode
                ? "Enter your name, email, and create a password"
                : devMode
                ? "Enter your developer PIN to continue"
                : multiUser ? "Enter your name and password to continue" : "Enter your password to continue"}
            </p>
          </div>

          <form onSubmit={handleSubmit} className="space-y-6">
            <div className={`space-y-3 transition-transform ${shake ? "animate-[shake_0.5s_ease-in-out]" : ""}`}>
              {claimMode ? (
                <>
                  <div className="relative">
                    <UserPlus className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                    <Input
                      type="text"
                      value={name}
                      onChange={(e) => setName(e.target.value)}
                      placeholder="Your name (exactly as given to you)"
                      className="pl-10 h-12 text-base bg-white/5 border-white/10"
                      data-testid="input-claim-name"
                      autoFocus
                      disabled={isClaimingAccount}
                    />
                  </div>
                  <div className="relative">
                    <Mail className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                    <Input
                      type="email"
                      value={claimEmail}
                      onChange={(e) => setClaimEmail(e.target.value)}
                      placeholder="Your email"
                      className="pl-10 h-12 text-base bg-white/5 border-white/10"
                      data-testid="input-claim-email"
                      disabled={isClaimingAccount}
                    />
                  </div>
                  <div className="relative">
                    <Shield className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                    <Input
                      type={showPassword ? "text" : "password"}
                      value={password}
                      onChange={(e) => setPassword(e.target.value)}
                      placeholder="Create a password"
                      className="pl-10 pr-10 h-12 text-base bg-white/5 border-white/10"
                      data-testid="input-claim-password"
                      disabled={isClaimingAccount}
                    />
                    <Button
                      type="button"
                      variant="ghost"
                      size="icon"
                      className="absolute right-1 top-1/2 -translate-y-1/2"
                      onClick={() => setShowPassword(!showPassword)}
                      tabIndex={-1}
                    >
                      {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                    </Button>
                  </div>
                  <div className="relative">
                    <Lock className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                    <Input
                      type={showPassword ? "text" : "password"}
                      value={confirmPassword}
                      onChange={(e) => setConfirmPassword(e.target.value)}
                      placeholder="Confirm password"
                      className="pl-10 h-12 text-base bg-white/5 border-white/10"
                      data-testid="input-claim-confirm-password"
                      disabled={isClaimingAccount}
                    />
                  </div>
                  <p className="text-[11px] text-muted-foreground/60 leading-relaxed">
                    Password must be at least 8 characters with 1 uppercase letter and 1 special character.
                  </p>
                </>
              ) : devMode ? (
                <div className="relative">
                  <Lock className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                  <Input
                    type="password"
                    value={devPin}
                    onChange={(e) => setDevPin(e.target.value)}
                    placeholder="Enter PIN"
                    className="pl-10 h-12 text-base bg-white/5 border-white/10 tracking-[0.3em] text-center font-mono"
                    data-testid="input-dev-pin"
                    autoFocus
                    maxLength={10}
                    disabled={isLoggingIn}
                  />
                </div>
              ) : (
                <>
                  {multiUser && (
                    <div className="relative">
                      <UserPlus className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                      <Input
                        type="text"
                        value={name}
                        onChange={(e) => setName(e.target.value)}
                        placeholder="Your name"
                        className="pl-10 h-12 text-base bg-white/5 border-white/10"
                        data-testid="input-login-name"
                        autoFocus
                        disabled={isLoggingIn}
                      />
                    </div>
                  )}
                  <div className="relative">
                    <Shield className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                    <Input
                      type={showPassword ? "text" : "password"}
                      value={password}
                      onChange={(e) => setPassword(e.target.value)}
                      placeholder="Enter password"
                      className="pl-10 pr-10 h-12 text-base bg-white/5 border-white/10"
                      data-testid="input-password"
                      autoFocus={!multiUser}
                      disabled={isLoggingIn}
                    />
                    <Button
                      type="button"
                      variant="ghost"
                      size="icon"
                      className="absolute right-1 top-1/2 -translate-y-1/2"
                      onClick={() => setShowPassword(!showPassword)}
                      data-testid="button-toggle-password-visibility"
                      tabIndex={-1}
                    >
                      {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                    </Button>
                  </div>
                </>
              )}

              {(loginError || errorMsg) && (
                <p className="text-center text-sm text-destructive" data-testid="text-login-error">
                  {errorMsg || "Incorrect credentials. Try again."}
                </p>
              )}
            </div>

            {!devMode && !claimMode && (
              <div className="flex items-center gap-3">
                <Switch
                  id="remember-me"
                  checked={rememberMe}
                  onCheckedChange={setRememberMe}
                  data-testid="toggle-remember-me"
                />
                <label
                  htmlFor="remember-me"
                  className="text-sm text-muted-foreground cursor-pointer select-none"
                >
