              ) : devMode ? (
                "Authenticate"
              ) : (
                "Unlock"
              )}
            </Button>

            <div className="flex flex-col items-center gap-2">
              {!devMode && (
                <button
                  type="button"
                  onClick={() => { setClaimMode(!claimMode); setErrorMsg(""); setPassword(""); setConfirmPassword(""); setClaimEmail(""); }}
                  className="text-xs text-primary/70 hover:text-primary transition-colors"
                  data-testid="button-claim-account-toggle"
                >
                  {claimMode ? "Already have a password? Log in" : "First time? Set up your account"}
                </button>
              )}
              {!claimMode && (
                <button
                  type="button"
                  onClick={() => { setDevMode(!devMode); setErrorMsg(""); setDevPin(""); setPassword(""); }}
                  className="text-xs text-muted-foreground/70 hover:text-primary transition-colors flex items-center gap-1.5 mt-1"
                  data-testid="button-dev-access-toggle"
                >
                  <Monitor className="w-3.5 h-3.5" />
                  {devMode ? "Back to login" : "Developer access"}
                </button>
              )}
            </div>

            <p className="text-[11px] text-muted-foreground/60 text-center leading-relaxed">
              By logging in, you agree to our use of secure session cookies.
              {rememberMe ? " Your session will persist for 30 days on this device." : " Your session will end when you close the browser."}
              {" "}We do not share your data with third parties. Your media files are stored securely in your private tenant space.
            </p>
          </form>
        </div>
      </motion.div>
    </div>
  );
}


function PasswordReset() {
  const { resetPassword, isResettingPassword } = useAuth();
  const [email, setEmail] = useState("");
  const [newPassword, setNewPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [step, setStep] = useState<"email" | "password" | "confirm">("email");
  const [error, setError] = useState("");
  const { toast } = useToast();

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const isEmailValid = emailRegex.test(email.trim());

  const hasMinLength = newPassword.length >= 8;
  const hasUppercase = /[A-Z]/.test(newPassword);
  const hasSpecialChar = /[!@#$%^&*()_+\-=\[\]{};':"\\|,.<>\/?`~]/.test(newPassword);
  const isPasswordValid = hasMinLength && hasUppercase && hasSpecialChar;

  const handleEmailContinue = () => {
    if (!isEmailValid) {
      setError("Please enter a valid email address");
      return;
    }
    setError("");
    setStep("password");
  };

  const handlePasswordContinue = () => {
    if (!isPasswordValid) return;
    setStep("confirm");
    setError("");
  };

  const handleSubmit = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (newPassword !== confirmPassword) {
      setError("Passwords don't match. Try again.");
      setConfirmPassword("");
      return;
    }

    try {
      await resetPassword({ newPassword, email: email.trim() });
      toast({
        title: "Account Set Up",
        description: "Your email and password have been saved securely.",
      });
    } catch (err: any) {
      setError(err.message || "Failed to set up account");
    }
  };

  const stepTitles = {
    email: "Set Up Your Account",
    password: "Create Your Password",
    confirm: "Confirm Password",
  };
  const stepDescs = {
    email: "Enter your email to secure your vault",
    password: "Create a strong password for your vault",
    confirm: "Enter the same password again to confirm",
  };

  const handleFormSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (step === "email") handleEmailContinue();
    else if (step === "password") handlePasswordContinue();
    else handleSubmit();
  };

  return (
    <div className="min-h-screen bg-background flex items-center justify-center p-4">
      <div className="max-w-sm w-full space-y-8">
        <div className="text-center">
          <div className="w-14 h-14 rounded-xl theme-gradient flex items-center justify-center mb-6 mx-auto shadow-lg shadow-primary/20">
            <KeyRound className="w-7 h-7 text-white" />
          </div>
          <h1 className="text-2xl font-display font-bold tracking-tight mb-1" data-testid="text-reset-title">
            {stepTitles[step]}
          </h1>
          <p className="text-sm text-muted-foreground">
            {stepDescs[step]}
          </p>
        </div>

        <form onSubmit={handleFormSubmit} className="space-y-6">
          {step === "email" && (
            <div className="space-y-4">
              <div className="relative">
                <Mail className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                <Input
                  type="email"
                  value={email}
                  onChange={(e) => { setEmail(e.target.value); setError(""); }}
                  placeholder="Your email address"
                  className="pl-10 h-12 text-base bg-white/5 border-white/10"
                  data-testid="input-reset-email"
                  autoFocus
                />
              </div>

              {error && (
                <p className="text-center text-sm text-destructive" data-testid="text-reset-error">{error}</p>
              )}

              <Button
                type="submit"
                data-testid="button-email-continue"
                disabled={!email.trim()}
                className="w-full h-12 text-base font-medium bg-primary text-white rounded-lg"
              >
                Continue
              </Button>
            </div>
          )}

          {step === "password" && (
            <div className="space-y-4">
              <div className="relative">
                <Shield className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                <Input
                  type={showPassword ? "text" : "password"}
                  value={newPassword}
                  onChange={(e) => setNewPassword(e.target.value)}
                  placeholder="New password"
                  className="pl-10 pr-10 h-12 text-base bg-white/5 border-white/10"
                  data-testid="input-new-password"
                  autoFocus
                  disabled={isResettingPassword}
                />
                <Button
                  type="button"
                  variant="ghost"
                  size="icon"
                  className="absolute right-1 top-1/2 -translate-y-1/2"
                  onClick={() => setShowPassword(!showPassword)}
                  data-testid="button-toggle-new-password-visibility"
                  tabIndex={-1}
                >
                  {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                </Button>
              </div>

              <div className="space-y-2 px-1">
                <div className="flex items-center gap-2">
                  {hasMinLength ? <Check className="w-4 h-4 text-green-500 shrink-0" /> : <X className="w-4 h-4 text-muted-foreground shrink-0" />}
                  <span className={`text-sm ${hasMinLength ? "text-green-500" : "text-muted-foreground"}`}>At least 8 characters</span>
                </div>
                <div className="flex items-center gap-2">
                  {hasUppercase ? <Check className="w-4 h-4 text-green-500 shrink-0" /> : <X className="w-4 h-4 text-muted-foreground shrink-0" />}
                  <span className={`text-sm ${hasUppercase ? "text-green-500" : "text-muted-foreground"}`}>At least 1 uppercase letter</span>
                </div>
                <div className="flex items-center gap-2">
                  {hasSpecialChar ? <Check className="w-4 h-4 text-green-500 shrink-0" /> : <X className="w-4 h-4 text-muted-foreground shrink-0" />}
                  <span className={`text-sm ${hasSpecialChar ? "text-green-500" : "text-muted-foreground"}`}>At least 1 special character (!@#$...)</span>
                </div>
              </div>

              {error && (
                <p className="text-center text-sm text-destructive" data-testid="text-reset-error">{error}</p>
              )}

              <div className="flex gap-2">
                <Button
                  type="button"
                  variant="outline"
                  className="flex-1 h-12 border-white/10"
                  onClick={() => { setStep("email"); setError(""); }}
                >
                  Back
                </Button>
                <Button
                  type="submit"
                  data-testid="button-password-continue"
                  disabled={!isPasswordValid || isResettingPassword}
                  className="flex-1 h-12 text-base font-medium bg-primary text-white rounded-lg"
                >
                  Continue
                </Button>
              </div>
            </div>
          )}

          {step === "confirm" && (
            <div className="space-y-4">
              <div className="relative">
                <Shield className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                <Input
                  type={showPassword ? "text" : "password"}
                  value={confirmPassword}
                  onChange={(e) => setConfirmPassword(e.target.value)}
                  placeholder="Confirm password"
                  className="pl-10 pr-10 h-12 text-base bg-white/5 border-white/10"
                  data-testid="input-confirm-password"
                  autoFocus
                  disabled={isResettingPassword}
                />
                <Button
                  type="button"
                  variant="ghost"
                  size="icon"
                  className="absolute right-1 top-1/2 -translate-y-1/2"
                  onClick={() => setShowPassword(!showPassword)}
                  data-testid="button-toggle-confirm-password-visibility"
                  tabIndex={-1}
                >
                  {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                </Button>
              </div>

              {error && (
                <p className="text-center text-sm text-destructive" data-testid="text-reset-error">{error}</p>
              )}

              <div className="flex gap-2">
                <Button
                  type="button"
                  variant="outline"
                  className="flex-1 h-12 border-white/10"
                  onClick={() => { setStep("password"); setConfirmPassword(""); setError(""); }}
                  disabled={isResettingPassword}
                >
                  Back
                </Button>
                <Button
                  type="submit"
                  data-testid="button-password-confirm"
                  disabled={confirmPassword.length < 8 || isResettingPassword}
                  className="flex-1 h-12 text-base font-medium bg-primary text-white rounded-lg"
                >
                  {isResettingPassword ? (
                    <Loader2 className="w-5 h-5 animate-spin" />
