  background-size: 200% 200%;
  animation: gradient-shift 10s ease infinite;
}

.card-glow {
  box-shadow: 0 0 0 1px hsl(var(--foreground) / 0.05),
              0 4px 24px -4px hsl(var(--primary) / 0.15),
              0 12px 48px -8px hsl(var(--primary) / 0.08);
}

.card-glow:hover {
