import { useState, useRef, useCallback } from "react";
import { useLocation } from "wouter";
import { type MediaResponse } from "@shared/routes";
import { type MediaCategory, MEDIA_CATEGORIES } from "@shared/schema";
import { Play, Calendar, Trash2, Heart, Film, Music, ImageIcon, FileText, File, Pencil, Eye, Clock, Scissors, SlidersHorizontal, Crop, Download, Share2, ListMusic, Sparkles, Loader2, Upload, Edit3, Tag, Users, Zap, Lock } from "lucide-react";
import featureUploadImg from "@assets/images/feature-upload.jpg";
import featureEditImg from "@assets/images/feature-edit.jpg";
import featureOrganizeImg from "@assets/images/feature-organize.jpg";
import featureShareImg from "@assets/images/feature-share.jpg";
import { UploadDialog } from "@/components/UploadDialog";
import { format } from "date-fns";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Tooltip, TooltipContent, TooltipTrigger } from "@/components/ui/tooltip";
import { useToggleFavorite, useDeleteMedia } from "@/hooks/use-media";
import { useHaptic } from "@/hooks/use-haptic";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { motion } from "framer-motion";
import {
  AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent,
  AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle, AlertDialogTrigger,
} from "@/components/ui/alert-dialog";
import { useToast } from "@/hooks/use-toast";

const CATEGORY_ICONS: Record<MediaCategory, any> = {
  video: Film,
  audio: Music,
  image: ImageIcon,
  document: FileText,
  other: File,
};

const CATEGORY_COLORS: Record<MediaCategory, string> = {
  video: "text-blue-400",
  audio: "text-green-400",
  image: "text-purple-400",
  document: "text-amber-400",
  other: "text-muted-foreground",
};

const PREMIUM_GRADIENT_CLASS: Record<MediaCategory, string> = {
  video: "premium-gradient-video",
  audio: "premium-gradient-audio",
  image: "premium-gradient-image",
  document: "premium-gradient-document",
  other: "premium-gradient-other",
};

const CATEGORY_ICON_GLOW: Record<MediaCategory, string> = {
  video: "shadow-blue-500/40",
  audio: "shadow-green-500/40",
  image: "shadow-purple-500/40",
  document: "shadow-amber-500/40",
  other: "shadow-white/20",
};

function formatDuration(seconds: number): string {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, "0")}`;
}

interface MediaGridProps {
  items: MediaResponse[];
  onPlay: (item: MediaResponse) => void;
  onEdit: (item: MediaResponse) => void;
  onShare?: (item: MediaResponse) => void;
  onAddToPlaylist?: (itemId: number) => void;
  bento?: boolean;
}

export function MediaGrid({ items, onPlay, onEdit, onShare, onAddToPlaylist, bento = true }: MediaGridProps) {
  if (items.length === 0) {
    return (
      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ duration: 0.5 }}
        className="flex flex-col items-center justify-center py-16 sm:py-20 px-4 text-center min-h-[600px]"
      >
        <div className="max-w-3xl w-full space-y-12">
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5, delay: 0.1 }}
            className="space-y-4"
          >
            <div className="w-20 h-20 sm:w-24 sm:h-24 rounded-full premium-gradient-image flex items-center justify-center mx-auto shadow-2xl card-glow">
              <Zap className="w-10 h-10 sm:w-12 sm:h-12 text-white" />
            </div>
            <h1 className="text-4xl sm:text-5xl font-display font-bold theme-gradient-text" data-testid="text-welcome-heading">
              Welcome to Your Vault
            </h1>
            <p className="text-lg text-muted-foreground max-w-xl mx-auto" data-testid="text-welcome-description">
              Your secure digital sanctuary for all your precious memories and creative content
            </p>
          </motion.div>

          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ duration: 0.5, delay: 0.2 }}
            className="grid grid-cols-1 sm:grid-cols-2 gap-4 sm:gap-5"
          >
            {[
              { icon: Upload, title: "Upload & Store", description: "Securely upload videos, photos, audio, and documents in one place", image: featureUploadImg },
              { icon: Edit3, title: "Edit & Create", description: "Trim videos, enhance images, and customize your content effortlessly", image: featureEditImg },
              { icon: Tag, title: "Organize & Tag", description: "Add tags, labels, and descriptions to keep everything organized", image: featureOrganizeImg },
              { icon: Users, title: "Share & Collaborate", description: "Share your vault with others and collaborate on projects", image: featureShareImg },
            ].map((feature, idx) => (
              <motion.div
                key={feature.title}
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.4, delay: 0.3 + idx * 0.08 }}
                className="glass-card rounded-md hover-elevate"
                data-testid={`card-feature-${idx + 1}`}
              >
                <div className="relative h-28 sm:h-32 overflow-hidden rounded-t-md">
                  <img src={feature.image} alt={feature.title} className="absolute inset-0 w-full h-full object-cover" loading="lazy" />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/90 via-black/50 to-black/20" />
                  <div className="absolute bottom-3 left-4 right-4 z-10">
                    <div className="flex items-center gap-2 mb-1">
                      <div className="p-1.5 rounded-md bg-primary/20 backdrop-blur-sm">
                        <feature.icon className="w-4 h-4 text-primary" />
                      </div>
                      <h3 className="font-display font-semibold text-white text-sm" data-testid={`text-feature-title-${idx + 1}`}>
                        {feature.title}
                      </h3>
                    </div>
                  </div>
                </div>
                <div className="p-4">
                  <p className="text-sm text-muted-foreground leading-relaxed" data-testid={`text-feature-description-${idx + 1}`}>
                    {feature.description}
                  </p>
                </div>
              </motion.div>
            ))}
          </motion.div>

          <motion.div
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5, delay: 0.6 }}
            className="space-y-6"
          >
            <UploadDialog>
              <Button 
                size="lg" 
                className="gap-2 rounded-md" 
                data-testid="button-upload-cta"
              >
                <Upload className="w-5 h-5" />
                Get Started - Upload Your First File
              </Button>
            </UploadDialog>

            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={{ duration: 0.5, delay: 0.8 }}
              className="space-y-3"
            >
              <p className="text-xs uppercase tracking-widest text-muted-foreground font-medium" data-testid="text-media-types-label">
                Supported Media Types
              </p>
              <div className="flex justify-center items-center gap-4 sm:gap-6 flex-wrap" data-testid="container-media-types">
                {[
                  { icon: Film, label: "Videos", testId: "icon-video-type" },
                  { icon: Music, label: "Audio", testId: "icon-audio-type" },
                  { icon: ImageIcon, label: "Images", testId: "icon-image-type" },
                  { icon: FileText, label: "Documents", testId: "icon-document-type" },
                ].map((media) => (
                  <motion.div
                    key={media.label}
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    transition={{ duration: 0.4, delay: 0.9 }}
                    className="flex flex-col items-center gap-1.5"
                    data-testid={media.testId}
                  >
                    <media.icon className="w-6 h-6 text-muted-foreground" />
                    <span className="text-xs text-muted-foreground">{media.label}</span>
                  </motion.div>
                ))}
              </div>
            </motion.div>
          </motion.div>
        </div>
      </motion.div>
    );
  }

  if (bento && items.length >= 3) {
    return <BentoMediaGrid items={items} onPlay={onPlay} onEdit={onEdit} onShare={onShare} onAddToPlaylist={onAddToPlaylist} />;
  }

  return (
    <div className="grid grid-cols-2 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4 sm:gap-5">
      {items.map((item, index) => (
        <MediaCard
          key={item.id}
          item={item}
          onPlay={() => onPlay(item)}
          onEdit={() => onEdit(item)}
          onShare={onShare ? () => onShare(item) : undefined}
          onAddToPlaylist={onAddToPlaylist && item.category === "audio" ? () => onAddToPlaylist(item.id) : undefined}
          index={index}
        />
      ))}
    </div>
  );
}

function BentoMediaGrid({ items, onPlay, onEdit, onShare, onAddToPlaylist }: { items: MediaResponse[]; onPlay: (item: MediaResponse) => void; onEdit: (item: MediaResponse) => void; onShare?: (item: MediaResponse) => void; onAddToPlaylist?: (itemId: number) => void }) {
  return (
    <div className="grid grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4 sm:gap-5 auto-rows-auto">
      {items.map((item, index) => {
        const isFeature = index === 0 || (index > 0 && index % 7 === 0);
        return (
          <div
            key={item.id}
            className={isFeature ? "col-span-2 row-span-2" : "col-span-1"}
          >
            <MediaCard
              item={item}
              onPlay={() => onPlay(item)}
              onEdit={() => onEdit(item)}
              onShare={onShare ? () => onShare(item) : undefined}
              onAddToPlaylist={onAddToPlaylist && item.category === "audio" ? () => onAddToPlaylist(item.id) : undefined}
              index={index}
              featured={isFeature}
            />
          </div>
        );
      })}
    </div>
  );
}

function MediaCard({ item, onPlay, onEdit, onShare, onAddToPlaylist, index, featured = false }: {
  item: MediaResponse;
  onPlay: () => void;
  onEdit: () => void;
  onShare?: () => void;
  onAddToPlaylist?: () => void;
  index: number;
  featured?: boolean;
}) {
  const [, navigate] = useLocation();
  const toggleFavorite = useToggleFavorite();
  const deleteMedia = useDeleteMedia();
  const { toast } = useToast();
  const haptic = useHaptic();
  const cardRef = useRef<HTMLDivElement>(null);
  const [tilt, setTilt] = useState({ x: 0, y: 0 });
  const [glare, setGlare] = useState({ x: 50, y: 50, opacity: 0 });
  const [captioningId, setCaptioningId] = useState<number | null>(null);

  const handleGenerateCaption = async (e: React.MouseEvent) => {
    e.stopPropagation();
    haptic("tap");
    setCaptioningId(item.id);
    try {
      const isVisual = cat === "image" || cat === "video";
      const body = isVisual
        ? { imageUrl: "/objects/" + item.url, title: item.title, category: item.category, style: "descriptive" }
        : { title: item.title, category: item.category, style: "descriptive" };

      const captionRes = await apiRequest("POST", "/api/ai/caption", body);
      const { caption } = await captionRes.json();

      await apiRequest("PATCH", `/api/media/${item.id}`, { description: caption });

      queryClient.invalidateQueries({ queryKey: ["/api/media"] });

      toast({ title: "AI Caption Generated", description: caption });
    } catch (err: any) {
      toast({ title: "Caption Error", description: err?.message || "Failed to generate caption", variant: "destructive" });
    } finally {
      setCaptioningId(null);
    }
  };

  const cat = (item.category as MediaCategory) || "other";
  const CatIcon = CATEGORY_ICONS[cat];
  const catColor = CATEGORY_COLORS[cat];
  const gradientClass = PREMIUM_GRADIENT_CLASS[cat];
  const glowClass = CATEGORY_ICON_GLOW[cat];

  const hasVisual = cat === "image" || ((cat === "video" || cat === "audio") && item.thumbnailUrl);

  const handleMouseMove = useCallback((e: React.MouseEvent) => {
    if (!cardRef.current) return;
    const rect = cardRef.current.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width;
    const y = (e.clientY - rect.top) / rect.height;
    setTilt({ x: (y - 0.5) * -6, y: (x - 0.5) * 6 });
    setGlare({ x: x * 100, y: y * 100, opacity: 0.12 });
  }, []);

  const handleMouseLeave = useCallback(() => {
    setTilt({ x: 0, y: 0 });
    setGlare({ x: 50, y: 50, opacity: 0 });
  }, []);

  const handleDelete = async () => {
    try {
      haptic("warning");
      await deleteMedia.mutateAsync(item.id);
      toast({ title: "Deleted", description: "Removed from your vault." });
    } catch {
      haptic("error");
      toast({ title: "Error", description: "Failed to delete.", variant: "destructive" });
    }
  };

  const handleFavorite = (e: React.MouseEvent) => {
    e.stopPropagation();
    haptic("tap");
    toggleFavorite.mutate({ id: item.id, isFavorite: !item.isFavorite });
  };

  const displayDate = item.fileDate
    ? format(new Date(item.fileDate), "MMM d, yyyy")
    : item.createdAt
    ? format(new Date(item.createdAt), "MMM d, yyyy")
    : null;

  return (
    <motion.div
      ref={cardRef}
      initial={{ opacity: 0, y: 20 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true, margin: "-40px" }}
      transition={{ delay: Math.min(index * 0.04, 0.3), duration: 0.4, ease: [0.25, 0.46, 0.45, 0.94] }}
      animate={{
        rotateX: tilt.x,
        rotateY: tilt.y,
      }}
      onMouseMove={handleMouseMove}
      onMouseLeave={handleMouseLeave}
      style={{ transformStyle: "preserve-3d", perspective: "800px" }}
      className="group relative rounded-xl overflow-visible card-glow transition-shadow duration-500 h-full"
      data-testid={`card-media-${item.id}`}
    >
      <div className="rounded-xl overflow-hidden h-full flex flex-col">
        <div
          className={`${featured ? "aspect-square" : "aspect-[4/3]"} relative cursor-pointer overflow-hidden flex items-center justify-center ${gradientClass}`}
          onClick={() => { haptic("tap"); onPlay(); }}
        >
          {cat === "image" ? (
            <img
              src={`/objects/${item.url}`}
              alt={item.title}
              className="absolute inset-0 w-full h-full object-cover"
              loading="lazy"
            />
          ) : (cat === "video" || cat === "audio") && item.thumbnailUrl ? (
            <img
              src={`/objects/${item.thumbnailUrl}`}
              alt={item.title}
              className="absolute inset-0 w-full h-full object-cover"
              loading="lazy"
            />
          ) : null}

          <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/20 to-transparent z-10" />

          {!hasVisual && (
            <div className="relative z-20 flex flex-col items-center gap-3">
              <div className={`p-5 rounded-2xl bg-white/10 backdrop-blur-md border border-white/20 shadow-2xl ${glowClass}`}>
                <CatIcon className={`${featured ? "w-12 h-12" : "w-10 h-10"} text-white drop-shadow-lg`} />
              </div>
              <span className="text-white/50 text-xs font-medium uppercase tracking-widest">{cat}</span>
            </div>
          )}

          {(cat === "video" || cat === "audio") && item.durationSeconds && (
            <div className="absolute bottom-2 right-2 z-20">
              <Badge variant="secondary" className="text-[10px] font-mono bg-black/60 backdrop-blur-md border-white/10 text-white no-default-hover-elevate no-default-active-elevate">
                <Clock className="w-3 h-3 mr-1" />
                {formatDuration(item.durationSeconds)}
              </Badge>
            </div>
          )}

          <div className="absolute inset-0 z-20 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity duration-200">
            <div className="w-14 h-14 rounded-full bg-white/15 backdrop-blur-md flex items-center justify-center border border-white/20 shadow-2xl">
              {cat === "video" ? (
                <Play className="w-6 h-6 text-white ml-0.5 fill-white" />
              ) : (
                <Eye className="w-6 h-6 text-white" />
              )}
            </div>
          </div>

          <div className="absolute top-2.5 left-2.5 z-20">
            <Badge variant="secondary" className="text-[10px] font-mono uppercase tracking-wider bg-black/50 backdrop-blur-md border-white/10 no-default-hover-elevate no-default-active-elevate">
              <CatIcon className={`w-3 h-3 mr-1 ${catColor}`} />
              {cat}
            </Badge>
          </div>

          <Tooltip>
            <TooltipTrigger asChild>
              <button
                onClick={handleFavorite}
                className="absolute top-2.5 right-2.5 z-20 p-2 sm:p-1.5 rounded-full bg-black/40 backdrop-blur-md border border-white/10"
                data-testid={`button-favorite-${item.id}`}
              >
                <Heart className={`w-4 h-4 sm:w-3.5 sm:h-3.5 ${item.isFavorite ? "fill-red-500 text-red-500" : "text-white/60"}`} />
              </button>
            </TooltipTrigger>
            <TooltipContent side="bottom" className="text-xs">
              {item.isFavorite ? "Remove from favorites" : "Add to favorites"}
            </TooltipContent>
          </Tooltip>
        </div>

        <div className="p-3.5 sm:p-4 bg-gradient-to-b from-black/60 to-card/90 backdrop-blur-sm flex-1">
          <div className="flex justify-between items-start gap-2">
            <div className="flex-1 min-w-0">
              <h3
                className={`font-display font-semibold ${featured ? "text-base sm:text-lg" : "text-sm sm:text-base"} text-white truncate cursor-pointer group-hover:text-primary transition-colors duration-200`}
                onClick={onPlay}
                title={item.title}
                data-testid={`text-title-${item.id}`}
              >
                {item.title}
              </h3>
              {item.artist && (
                <p className="text-[11px] text-muted-foreground truncate mt-0.5" data-testid={`text-artist-${item.id}`}>
                  {item.artist}
                </p>
              )}
              <div className="flex items-center gap-2 mt-1.5 text-[11px] text-muted-foreground">
                {displayDate && (
                  <span className="flex items-center gap-1">
                    <Calendar className="w-3 h-3" />
                    {displayDate}
                  </span>
                )}
                {item.label && (
                  <Badge variant="outline" className="text-[10px] py-0 px-1.5 border-white/10 no-default-hover-elevate no-default-active-elevate">
                    {item.label}
                  </Badge>
                )}
              </div>
            </div>

            <div className="flex items-center gap-0.5 shrink-0">
              <Tooltip>
                <TooltipTrigger asChild>
                  <Button
                    variant="ghost"
                    size="icon"
                    onClick={(e) => {
                      e.stopPropagation();
                      haptic("tap");
                      const link = document.createElement("a");
                      link.href = `/objects/${item.url}`;
                      link.download = item.filename || item.title;
                      link.click();
                    }}
                    data-testid={`button-download-${item.id}`}
                  >
                    <Download className="w-3.5 h-3.5" />
                  </Button>
                </TooltipTrigger>
                <TooltipContent side="bottom" className="text-xs">Download</TooltipContent>
              </Tooltip>
              {onShare && (
                <Tooltip>
                  <TooltipTrigger asChild>
                    <Button
                      variant="ghost"
                      size="icon"
                      onClick={(e) => { e.stopPropagation(); haptic("tap"); onShare(); }}
                      data-testid={`button-share-${item.id}`}
                    >
                      <Share2 className="w-3.5 h-3.5" />
                    </Button>
                  </TooltipTrigger>
                  <TooltipContent side="bottom" className="text-xs">Share</TooltipContent>
                </Tooltip>
              )}
              {onAddToPlaylist && (
                <Tooltip>
                  <TooltipTrigger asChild>
                    <Button
                      variant="ghost"
                      size="icon"
                      onClick={(e) => { e.stopPropagation(); haptic("tap"); onAddToPlaylist(); }}
                      data-testid={`button-add-playlist-${item.id}`}
                    >
                      <ListMusic className="w-3.5 h-3.5" />
                    </Button>
                  </TooltipTrigger>
                  <TooltipContent side="bottom" className="text-xs">Add to Playlist</TooltipContent>
                </Tooltip>
              )}
              <Tooltip>
                <TooltipTrigger asChild>
                  <Button
                    variant="ghost"
                    size="icon"
                    onClick={handleGenerateCaption}
                    disabled={captioningId === item.id}
                    aria-label="Generate AI caption"
                    data-testid={`button-ai-caption-${item.id}`}
                  >
                    {captioningId === item.id ? (
                      <Loader2 className="w-3.5 h-3.5 animate-spin" />
                    ) : (
                      <Sparkles className="w-3.5 h-3.5" />
                    )}
                  </Button>
                </TooltipTrigger>
                <TooltipContent side="bottom" className="text-xs">Generate AI caption</TooltipContent>
              </Tooltip>
              <Tooltip>
                <TooltipTrigger asChild>
                  <Button
                    variant="ghost"
                    size="icon"
                    onClick={(e) => { e.stopPropagation(); haptic("tap"); onEdit(); }}
                    data-testid={`button-edit-${item.id}`}
                  >
                    <Pencil className="w-3.5 h-3.5" />
                  </Button>
                </TooltipTrigger>
                <TooltipContent side="bottom" className="text-xs">Edit details</TooltipContent>
              </Tooltip>
              <AlertDialog>
                <Tooltip>
                  <TooltipTrigger asChild>
                    <AlertDialogTrigger asChild>
                      <Button variant="ghost" size="icon" data-testid={`button-delete-${item.id}`}>
                        <Trash2 className="w-3.5 h-3.5" />
                      </Button>
                    </AlertDialogTrigger>
                  </TooltipTrigger>
                  <TooltipContent side="bottom" className="text-xs">Delete file</TooltipContent>
                </Tooltip>
                <AlertDialogContent className="bg-background border-white/10">
                  <AlertDialogHeader>
                    <AlertDialogTitle>Delete this file?</AlertDialogTitle>
                    <AlertDialogDescription>This will permanently remove "{item.title}" from your vault.</AlertDialogDescription>
                  </AlertDialogHeader>
                  <AlertDialogFooter>
                    <AlertDialogCancel>Cancel</AlertDialogCancel>
                    <AlertDialogAction onClick={handleDelete} className="bg-destructive text-white">Delete</AlertDialogAction>
                  </AlertDialogFooter>
                </AlertDialogContent>
              </AlertDialog>
            </div>
          </div>

          {(cat === "video" || cat === "audio" || cat === "image") && (
            <Button
              variant="outline"
              size="sm"
              className="w-full mt-2.5 gap-1.5 text-xs border-white/10 text-muted-foreground"
              onClick={(e) => {
                e.stopPropagation();
                haptic("tap");
                navigate(`/editor/${cat}/${item.id}`);
              }}
              data-testid={`button-open-editor-${item.id}`}
            >
              {cat === "video" && <Scissors className="w-3 h-3" />}
              {cat === "audio" && <SlidersHorizontal className="w-3 h-3" />}
              {cat === "image" && <Crop className="w-3 h-3" />}
              {cat === "video" ? "Trim & Edit" : cat === "audio" ? "Edit Audio" : "Edit Image"}
            </Button>
          )}

          {item.tags && item.tags.length > 0 && (
            <div className="flex flex-wrap gap-1 mt-2">
              {item.tags.slice(0, 3).map(tag => (
                <Badge key={tag} variant="secondary" className="text-[10px] py-0 px-1.5 no-default-hover-elevate no-default-active-elevate">{tag}</Badge>
              ))}
              {item.tags.length > 3 && (
                <Badge variant="secondary" className="text-[10px] py-0 px-1.5 no-default-hover-elevate no-default-active-elevate">+{item.tags.length - 3}</Badge>
              )}
            </div>
          )}
        </div>
      </div>

      <div
        className="absolute inset-0 rounded-xl pointer-events-none z-30"
        style={{
          background: `radial-gradient(circle at ${glare.x}% ${glare.y}%, rgba(255,255,255,${glare.opacity}), transparent 60%)`,
          transition: "opacity 0.3s ease",
        }}
      />
    </motion.div>
  );
}

client/src/components/EditMediaDialog.ts.content:
import { useState, useEffect } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Badge } from "@/components/ui/badge";
import { useUpdateMedia } from "@/hooks/use-media";
import { Loader2, X } from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import type { MediaResponse } from "@shared/routes";

interface EditMediaDialogProps {
  item: MediaResponse | null;
  open: boolean;
  onOpenChange: (open: boolean) => void;
}

export function EditMediaDialog({ item, open, onOpenChange }: EditMediaDialogProps) {
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [label, setLabel] = useState("");
  const [tagInput, setTagInput] = useState("");
  const [tags, setTags] = useState<string[]>([]);
  const [artist, setArtist] = useState("");
  const [venue, setVenue] = useState("");
  const [tour, setTour] = useState("");
  const [eventDate, setEventDate] = useState("");

  const updateMedia = useUpdateMedia();
  const { toast } = useToast();

  useEffect(() => {
    if (item && open) {
      setTitle(item.title);
      setDescription(item.description || "");
      setLabel(item.label || "");
      setTags(item.tags || []);
      setTagInput("");
      setArtist(item.artist || "");
      setVenue(item.venue || "");
      setTour(item.tour || "");
      setEventDate(item.eventDate ? new Date(item.eventDate).toISOString().split("T")[0] : "");
    }
  }, [item, open]);

  const handleAddTag = () => {
    const trimmed = tagInput.trim();
    if (trimmed && !tags.includes(trimmed)) {
      setTags([...tags, trimmed]);
      setTagInput("");
    }
  };

  const handleTagKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === "Enter" || e.key === ",") {
      e.preventDefault();
      handleAddTag();
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!item) return;

    try {
      await updateMedia.mutateAsync({
        id: item.id,
        updates: {
          title,
          description: description || undefined,
          label: label || undefined,
          tags: tags.length > 0 ? tags : undefined,
          artist: artist || undefined,
          venue: venue || undefined,
          tour: tour || undefined,
          eventDate: eventDate ? new Date(eventDate).toISOString() : undefined,
        },
      });
      toast({ title: "Updated", description: "Changes saved." });
      onOpenChange(false);
    } catch {
      toast({ title: "Error", description: "Failed to save changes.", variant: "destructive" });
    }
  };

  if (!item) return null;

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-md max-h-[90vh] overflow-y-auto bg-background border-white/10 text-foreground">
        <DialogHeader>
          <DialogTitle className="text-xl font-display font-bold">Edit Details</DialogTitle>
        </DialogHeader>

        <form onSubmit={handleSubmit} className="space-y-5 mt-2">
          <div className="space-y-2">
            <Label htmlFor="edit-title" className="text-xs font-medium uppercase tracking-wider text-muted-foreground">Title</Label>
            <Input
              id="edit-title"
              data-testid="input-edit-title"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              className="bg-white/5 border-white/10 focus:border-primary/50"
              required
            />
          </div>

          <div className="space-y-2">
            <Label htmlFor="edit-label" className="text-xs font-medium uppercase tracking-wider text-muted-foreground">Label</Label>
            <Input
              id="edit-label"
